// ─── BANQUES DE QUESTIONS ───

export const QB_ABM_PREANA = [
  {id:"abm_pa1",prompt:"Quel tube (bouchon violet) est utilisé pour la NFS ?",choices:["Tube sec (gel)","Tube EDTA","Tube citrate","Tube fluorure"],answer:1,diff:1,explication:"L'EDTA (éthylène diamine tétra-acétate) chélate le calcium, empêchant la coagulation sans lyser les cellules. Indispensable pour NFS, réticulocytes, frottis.",tags:["Pré-analytique","Tubes","NFS"]},
  {id:"abm_pa2",prompt:"Le tube citraté (bouchon bleu) est utilisé pour :",choices:["La glycémie","L'ionogramme","Les examens d'hémostase (TP, TCA, fibrinogène)","La NFS"],answer:2,diff:1,explication:"Le citrate de sodium chélate le calcium de façon réversible. Le remplissage au trait est impératif (rapport 9:1 sang/citrate) sinon les résultats d'hémostase sont faussés.",tags:["Pré-analytique","Tubes","Hémostase"]},
  {id:"abm_pa3",prompt:"La règle des 8 identificateurs du patient comprend obligatoirement :",choices:["Nom, prénom, date de naissance, sexe","Uniquement le nom et le numéro de dossier","Nom de naissance, prénom usuel, date de naissance, sexe, adresse, médecin","Nom, prénom, IPP, numéro de sécu, date de naissance, sexe, adresse, médecin prescripteur"],answer:3,diff:2,explication:"L'identification du patient est un acte critique. Les 8 identificateurs permettent la traçabilité et la sécurité. Tout tube mal identifié doit être refusé.",tags:["Pré-analytique","Identification","Sécurité"]},
  {id:"abm_pa4",prompt:"L'hémolyse dans un échantillon sanguin fausse en priorité :",choices:["La glycémie","Le dosage du potassium (élévation fausse)","Le temps de prothrombine","La numération des plaquettes"],answer:1,diff:2,explication:"L'hémolyse libère le potassium intracellulaire des érythrocytes → pseudohyperkaliémie. Elle interfère aussi sur LDH, ASAT, bilirubine, créatinine kinase.",tags:["Pré-analytique","Hémolyse","Interférences"]},
  {id:"abm_pa5",prompt:"Le délai maximal de conservation à température ambiante d'un prélèvement pour NFS est :",choices:["30 minutes","6 à 8 heures","24 heures","72 heures"],answer:1,diff:2,explication:"Pour NFS : analyse idéalement <4h. Conservation possible 6-8h à TA (certains paramètres se dégradent : plaquettes, réticulocytes). Refaire si > 24h.",tags:["Pré-analytique","Conservation","NFS"]},
  {id:"abm_pa6",prompt:"La lipémie (échantillon lactescent) interfère principalement sur :",choices:["L'hémogramme","Les dosages spectrophotométriques (turbidité fausse les mesures optiques)","L'antibiogramme","La coagulation"],answer:1,diff:2,explication:"Les lipides diffusent la lumière → absorbance parasite. Fausse bilirubine, protéines totales, certaines enzymes. Ultracentrifugation ou dilution parfois nécessaires.",tags:["Pré-analytique","Lipémie","Interférences"]},
  {id:"abm_pa7",prompt:"Pour un prélèvement capillaire chez un nourrisson, le site recommandé est :",choices:["La pulpe du doigt","Le lobe de l'oreille","La face latérale du talon","La veine cubitale"],answer:2,diff:1,explication:"Chez le nourrisson < 1 an : face latérale du talon (talonnette). Évite les nerfs et artères. Profondeur maximale 2.4 mm pour éviter l'os.",tags:["Pré-analytique","Prélèvement","Pédiatrie"]},
  {id:"abm_pa8",prompt:"L'ordre de remplissage des tubes lors d'une ponction veineuse est :",choices:["Citrate → EDTA → Sec/Gel → Héparine → Fluorure","EDTA → Citrate → Sec → Héparine → Fluorure","Hémocultures → Citrate → Sec/Gel → Héparine → EDTA → Fluorure","Sec/Gel → Citrate → EDTA → Héparine → Fluorure"],answer:2,diff:2,explication:"Norme CLSI/H3 : hémocultures (si prescrites) → citrate (rapport précis) → sec/gel → héparine → EDTA → fluorure. Evite la contamination croisée des additifs.",tags:["Pré-analytique","Ordre tubes","Phlebotomie"]},
  {id:"abm_pa9",prompt:"Le tube fluoré (bouchon gris) est spécifiquement utilisé pour :",choices:["L'hémostase","La glycémie (inhibe la glycolyse)","La culture cellulaire","L'ionogramme"],answer:1,diff:1,explication:"Le fluorure de sodium inhibe les enzymes glycolytiques. Sans ce tube, la glycémie baisse d'environ 0.6 mmol/L par heure à température ambiante.",tags:["Pré-analytique","Tubes","Glycémie"]},
  {id:"abm_pa10",prompt:"Un garrot appliqué plus de 2 minutes peut entraîner :",choices:["Une dilution du sang","Une stase veineuse → hémoconcentration et pseudohyperkaliémie","Une baisse du potassium","Un allongement du temps de Quick"],answer:1,diff:2,explication:"Stase prolongée → hémoconcentration (albumine, Ca, K↑), pseudohyperkaliémie par hémolyse mécanique. Garrot < 1 min recommandé.",tags:["Pré-analytique","Garrot","Interférences"]},
  {id:"abm_pa11",prompt:"La phase pré-analytique représente quelle proportion des erreurs en biologie médicale ?",choices:["10-20%","40-70%","< 5%","80-90%"],answer:1,diff:2,explication:"Selon la littérature, 40-70% des erreurs biologiques surviennent en phase pré-analytique (identification, prélèvement, transport, centrifugation). D'où son importance critique.",tags:["Pré-analytique","Qualité","Erreurs"]},
  {id:"abm_pa12",prompt:"Un prélèvement pour ECBU doit être analysé dans un délai de :",choices:["Immédiatement","< 2 heures à TA ou < 24h à +4°C","48 heures à TA","1 semaine congelé"],answer:1,diff:1,explication:"Delai < 2h à température ambiante (sinon multiplication bactérienne → faux positifs) ou conservation au froid +4°C < 24h.",tags:["Pré-analytique","ECBU","Conservation"]},
  {id:"abm_pa13",prompt:"Le recueil des urines du matin pour ECBU est préconisé car :",choices:["C'est plus pratique","Les urines sont concentrées et la bactériurie est plus représentative","C'est plus stérile","Le patient est à jeun"],answer:1,diff:1,explication:"Urines de la nuit (temps de séjour vésical ≥ 4h) → concentration optimale des bactéries. Premier jet éliminé (flore urétrale), milieu de jet recueilli.",tags:["Pré-analytique","ECBU","Recueil"]},
  {id:"abm_pa14",prompt:"La centrifugation standard pour obtenir le plasma est :",choices:["200g pendant 5 min","2000-3000 g pendant 10-15 min","10 000 g pendant 30 min","400 g pendant 1h"],answer:1,diff:2,explication:"Centrifugation standard plasma : 2000-3000 × g, 10-15 min, température ambiante. Au-delà = plasma pauvre en plaquettes. Tube sec/gel : obtention sérum après coagulation.",tags:["Pré-analytique","Centrifugation","Plasma"]},
  {id:"abm_pa15",prompt:"L'ictère (bilirubinémie élevée) interfère avec :",choices:["La NFS uniquement","Les méthodes spectrophotométriques aux longueurs d'onde proches de 450 nm","L'antibiogramme","L'hémostase uniquement"],answer:1,diff:2,explication:"Bilirubine absorbe à ~460 nm. Interfère avec les dosages utilisant cette plage (créatinine Jaffé, certaines méthodes enzymatiques). Nécessite méthodes alternatives ou corrections.",tags:["Pré-analytique","Ictère","Interférences"]},
];

export const QB_ABM_HEMATO = [
  {id:"abm_h1",prompt:"Les valeurs normales d'hémoglobine chez l'homme adulte sont :",choices:["8-10 g/dL","12-14 g/dL","13-17 g/dL","18-22 g/dL"],answer:2,diff:1,explication:"Homme adulte : Hb 13-17 g/dL. Femme adulte : 12-16 g/dL. Enfant : variable selon l'âge. En dessous = anémie, au-dessus = polyglobulie.",tags:["Hématologie","Hémoglobine","NFS"]},
  {id:"abm_h2",prompt:"Le VGM (Volume Globulaire Moyen) normal est d'environ :",choices:["60-70 fL","80-100 fL","110-120 fL","40-50 fL"],answer:1,diff:1,explication:"VGM normal : 80-100 fL. < 80 fL = microcytose (carence martiale, thalassémie). > 100 fL = macrocytose (carence folates/B12, hypothyroïdie, alcool).",tags:["Hématologie","VGM","Anémie"]},
  {id:"abm_h3",prompt:"Une anémie microcytaire hypochrome oriente vers :",choices:["Carence en vitamine B12","Carence martiale (fer) ou thalassémie","Hémolyse aiguë","Aplasie médullaire"],answer:1,diff:1,explication:"Microcytose + hypochromie = trouble synthèse hémoglobine. 1ère cause : carence en fer (saignement occulte chez adulte). Aussi : thalassémie, anémie inflammatoire chronique.",tags:["Hématologie","Anémie","VGM","CCMH"]},
  {id:"abm_h4",prompt:"La formule leucocytaire normale chez l'adulte : les polynucléaires neutrophiles représentent :",choices:["5-10%","20-30%","50-70%","80-90%"],answer:2,diff:1,explication:"PNN : 50-70% des leucocytes. Eosinophiles : 1-4%. Basophiles : < 1%. Lymphocytes : 20-30%. Monocytes : 2-8%. PNN = 1ère ligne défense anti-bactérienne.",tags:["Hématologie","Formule leucocytaire","NFS"]},
  {id:"abm_h5",prompt:"Une hyperéosinophilie (éosinophiles > 500/µL) oriente vers :",choices:["Infection bactérienne sévère","Parasitose, allergie ou hémopathie","Infection virale aiguë","Aplasie médullaire"],answer:1,diff:2,explication:"Règle des 3A : Allergie, Auto-immunité, Asthme + Parasitose (helminthes tisulaires) + Hémopathie (lymphome). Différence éosinophile : allergie vs invasion tissulaire parasitaire.",tags:["Hématologie","Éosinophilie","NFS"]},
  {id:"abm_h6",prompt:"Le temps de Quick (TP) explore :",choices:["La voie intrinsèque de la coagulation","La voie extrinsèque (facteurs I, II, V, VII, X)","Les plaquettes","La fibrinolyse"],answer:1,diff:2,explication:"TP/TQ explore voie extrinsèque (thromboplastine tissulaire) : facteurs I (fibrinogène), II (prothrombine), V, VII, X. Base du suivi AVK (INR = TP standardisé).",tags:["Hématologie","Hémostase","TP","Coagulation"]},
  {id:"abm_h7",prompt:"Le TCA (Temps de Céphaline Activé) explore :",choices:["La voie extrinsèque","La voie intrinsèque (facteurs VIII, IX, XI, XII)","La voie commune uniquement","Les plaquettes"],answer:1,diff:2,explication:"TCA explore voie intrinsèque + commune : facteurs VIII, IX, XI, XII (voie intrinsèque) + I, II, V, X (commune). Allongé dans hémophilies A (VIII) et B (IX), traitement héparine.",tags:["Hématologie","TCA","Hémostase","Hémophilie"]},
  {id:"abm_h8",prompt:"Un INR thérapeutique pour un patient sous AVK en FANV doit se situer entre :",choices:["1.0-1.5","2.0-3.0","3.5-4.5","5.0-6.0"],answer:1,diff:1,explication:"INR 2-3 = zone thérapeutique pour FANV, MTEV, valve mécanique standard. < 2 = sous-anticoagulation (risque thrombotique). > 3 = sur-anticoagulation (risque hémorragique).",tags:["Hématologie","INR","AVK","Anticoagulants"]},
  {id:"abm_h9",prompt:"Les réticulocytes sont :",choices:["Des globules blancs immatures","Des érythrocytes jeunes contenant encore des ARN ribosomiques (granulations bleues en coloration supravitale)","Des plaquettes activées","Des cellules souches hématopoïétiques"],answer:1,diff:2,explication:"Réticulocytes = GR jeunes en circulation (1-2 jours post-libération médullaire). Normaux : 25-100 G/L. Augmentés = régénération (hémolyse, saignement). Abaissés = aplasie ou carence.",tags:["Hématologie","Réticulocytes","Régénération"]},
  {id:"abm_h10",prompt:"Le frottis sanguin coloré au May-Grünwald Giemsa (MGG) permet de :",choices:["Mesurer l'hémoglobine","Observer la morphologie cellulaire et détecter anomalies (drépanocytes, schizocytes, blastes)","Doser les protéines plasmatiques","Mesurer la coagulation"],answer:1,diff:1,explication:"MGG : coloration de référence pour morphologie sanguine. Identifie corps de Howell-Jolly, schizocytes (CIVD, MAT), drépanocytes, blastes (leucémies), parasites intracellulaires.",tags:["Hématologie","Frottis","MGG","Morphologie"]},
  {id:"abm_h11",prompt:"Le fibrinogène normal est de :",choices:["< 1 g/L","2-4 g/L","5-8 g/L","10-12 g/L"],answer:1,diff:1,explication:"Fibrinogène normal : 2-4 g/L. Facteur I, substrat de la thrombine. Abaissé : CIVD, hépatopathie sévère. Élevé : syndrome inflammatoire (réactant de phase aiguë).",tags:["Hématologie","Fibrinogène","Coagulation"]},
  {id:"abm_h12",prompt:"Une thrombopénie < 50 G/L expose à un risque :",choices:["De thrombose veineuse","Hémorragique (saignements muqueux, purpura)","D'infection sévère","D'anémie hémolytique"],answer:1,diff:2,explication:"Plaquettes normales : 150-400 G/L. < 50 G/L = risque hémorragique spontané (saignements muqueux). < 20 G/L = risque hémorragique grave. Causes : PTI, CIVD, médicaments.",tags:["Hématologie","Thrombopénie","Plaquettes"]},
  {id:"abm_h13",prompt:"La drépanocytose (HbS) se caractérise par :",choices:["Un VGM abaissé et des globules rouges en cible","Des globules rouges en faucille (drépanocytes) lors de la désoxygénation","Une macrocytose avec mégaloblastes","Un temps de Quick allongé"],answer:1,diff:2,explication:"Drépanocytose : mutation β-globine (Val→Glu en position 6). HbS polymérise à la désoxygénation → drépanocytes rigides → occlusions vasculaires, hémolyse chronique.",tags:["Hématologie","Drépanocytose","HbS","Hémoglobinopathie"]},
  {id:"abm_h14",prompt:"Le D-Dimère est un marqueur de :",choices:["La synthèse de fibrinogène","La fibrinolyse (dégradation de la fibrine réticulée)","La synthèse des plaquettes","L'activité plaquettaire"],answer:1,diff:2,explication:"D-Dimères = produits de dégradation de la fibrine par la plasmine. Élevés dans CIVD, EP, TVP (VPN élevée → utile pour exclure EP si < 500 µg/L). Peu spécifique.",tags:["Hématologie","D-Dimères","Fibrinolyse","CIVD"]},
  {id:"abm_h15",prompt:"En cas de suspicion de CIVD (Coagulation Intravasculaire Disséminée), on attend :",choices:["TP normal, TCA normal, plaquettes normales","TP abaissé, TCA allongé, plaquettes basses, fibrinogène bas, D-Dimères élevés","TP élevé, TCA court, plaquettes élevées","Uniquement une anémie isolée"],answer:1,diff:3,explication:"CIVD = activation pathologique coagulation + fibrinolyse : ↓TP, ↑TCA, ↓plaquettes, ↓fibrinogène, ↑D-Dimères, ↑PDF. Traitement de la cause en urgence.",tags:["Hématologie","CIVD","Bilan hémostase"]},
];

export const QB_ABM_BIOCHIMIE = [
  {id:"abm_bc1",prompt:"La glycémie à jeun normale est de :",choices:["< 5.6 mmol/L (1.0 g/L)","3.9-5.6 mmol/L (0.70-1.10 g/L)","7-11 mmol/L","< 3 mmol/L"],answer:1,diff:1,explication:"Glycémie veineuse à jeun (8h min) normale : 3.9-5.6 mmol/L (0.70-1.10 g/L). > 6.1 mmol/L = hyperglycémie à jeun. > 7 mmol/L deux fois = diabète.",tags:["Biochimie","Glycémie","Diabète"]},
  {id:"abm_bc2",prompt:"L'HbA1c reflète la glycémie moyenne des :",choices:["3 derniers jours","3 dernières semaines","2-3 derniers mois","6 derniers mois"],answer:2,diff:1,explication:"HbA1c = hémoglobine glyquée. Liée à la durée de vie des GR (120 jours). Reflète la glycémie moyenne des 2-3 derniers mois. Objectif diabétique : < 7% (53 mmol/mol).",tags:["Biochimie","HbA1c","Diabète","Suivi"]},
  {id:"abm_bc3",prompt:"La créatinine sérique est un marqueur de :",choices:["La fonction hépatique","La fonction rénale (filtration glomérulaire)","La fonction pancréatique","L'état nutritionnel"],answer:1,diff:1,explication:"Créatinine = déchet du métabolisme musculaire, filtré par le rein. Élevée = insuffisance rénale. DFG estimé par formule CKD-EPI (ou MDRD) à partir de la créatinine.",tags:["Biochimie","Créatinine","Rein","DFG"]},
  {id:"abm_bc4",prompt:"Les ALAT (SGPT) sont principalement élevées en cas de :",choices:["Atteinte musculaire","Atteinte hépatique (cytolyse hépatocytaire)","Atteinte rénale","Atteinte pancréatique"],answer:1,diff:1,explication:"ALAT (Alanine aminotransférase) = enzyme cytoplasmique hépatocytaire. Très spécifique du foie. Élevées dans hépatites virales, alcooliques, auto-immunes. ASAT moins spécifique (muscles, cœur).",tags:["Biochimie","Transaminases","ALAT","Foie"]},
  {id:"abm_bc5",prompt:"La bilirubine totale se compose de :",choices:["Bilirubine libre seulement","Bilirubine libre (indirecte/non conjuguée) + bilirubine conjuguée (directe)","Bilirubine conjuguée seulement","Urobiline et stercobiline"],answer:1,diff:2,explication:"Bilirubine libre : non conjuguée, insoluble, liée albumine. Conjuguée (directe) : hydrosoluble, éliminée dans la bile. Ictère hémolytique : ↑libre. Ictère cholestatique : ↑conjuguée.",tags:["Biochimie","Bilirubine","Ictère","Foie"]},
  {id:"abm_bc6",prompt:"La troponine I ou T est le marqueur de référence de :",choices:["L'embolie pulmonaire","L'infarctus du myocarde (nécrose myocardique)","L'insuffisance hépatique","La pancréatite aiguë"],answer:1,diff:1,explication:"Troponine cardiaque (cTnI, cTnT) : très spécifique du myocarde. Élévation dès H2-4 après nécrose, pic H12-24, reste élevée 5-14 jours. Critère diagnostique de l'IDM.",tags:["Biochimie","Troponine","IDM","Marqueurs cardiaques"]},
  {id:"abm_bc7",prompt:"La TSH (Thyréostimuline) est le marqueur de premier niveau pour :",choices:["Le diabète","La thyroïde (seul examen de débrouillage)","La surrénale","L'hypophyse"],answer:1,diff:1,explication:"TSH = hormone hypophysaire qui stimule la thyroïde. TSH basse + T4 élevée = hyperthyroïdie. TSH élevée + T4 basse = hypothyroïdie. Seul examen prescrit en première intention.",tags:["Biochimie","TSH","Thyroïde","Hormones"]},
  {id:"abm_bc8",prompt:"Un ionogramme normal montre une natrémie de :",choices:["100-110 mmol/L","136-145 mmol/L","150-165 mmol/L","200-220 mmol/L"],answer:1,diff:1,explication:"Natrémie normale : 136-145 mmol/L. Ion extracellulaire majoritaire. < 136 = hyponatrémie. > 145 = hypernatrémie. La natrémie reflète l'état d'hydratation.",tags:["Biochimie","Ionogramme","Natrémie"]},
  {id:"abm_bc9",prompt:"La kaliémie normale est de :",choices:["1.5-2.5 mmol/L","3.5-5.0 mmol/L","6.0-7.0 mmol/L","0.5-1.0 mmol/L"],answer:1,diff:1,explication:"Kaliémie normale : 3.5-5.0 mmol/L. Ion intracellulaire majoritaire. Hypokaliémie (< 3.5) : crampes, troubles ECG. Hyperkaliémie (> 5.5) : risque d'arythmie grave.",tags:["Biochimie","Ionogramme","Kaliémie"]},
  {id:"abm_bc10",prompt:"La CRP (Protéine C-Réactive) est :",choices:["Un marqueur de l'anémie","Un réactant de phase aiguë (marqueur d'inflammation/infection bactérienne)","Un marqueur tumoral","Un marqueur de coagulation"],answer:1,diff:1,explication:"CRP synthétisée par le foie en réponse à l'IL-6. S'élève en quelques heures. > 10 mg/L = inflammation. > 100 mg/L oriente vers infection bactérienne sévère. Utile pour suivi antibiothérapie.",tags:["Biochimie","CRP","Inflammation","Infection"]},
  {id:"abm_bc11",prompt:"L'électrophorèse des protéines plasmatiques sépare les protéines en :",choices:["2 fractions","5 fractions (albumine, α1, α2, β, γ-globulines)","10 fractions","1 seule bande"],answer:1,diff:2,explication:"EPP : albumine (60%) + 4 globulines. Anomalies : ↑γ polyclonale (infection chronique), pic monoclonal (myélome), ↓albumine (malnutrition, hépatopathie).",tags:["Biochimie","Électrophorèse","Protéines"]},
  {id:"abm_bc12",prompt:"Le PSA (Antigène Spécifique de la Prostate) est utilisé pour :",choices:["Le dépistage du cancer du côlon","Le suivi du cancer de la prostate","Le diagnostic du lupus","Le dépistage du cancer du sein"],answer:1,diff:1,explication:"PSA = glycoprotéine produite par l'épithélium prostatique. PSA total > 4 ng/mL = investigation. Rapport PSA libre/total < 15% oriente vers cancer. Outil de suivi après traitement.",tags:["Biochimie","PSA","Cancer","Marqueurs tumoraux"]},
  {id:"abm_bc13",prompt:"L'amylase et la lipase sont élevées en cas de :",choices:["Infarctus du myocarde","Insuffisance rénale","Pancréatite aiguë","Hépatite virale"],answer:2,diff:1,explication:"Pancréatite aiguë : amylase > 3N et lipase > 3N (lipase plus spécifique et plus longtemps élevée). Aussi élevées dans obstruction canal pancréatique, perforation digestive.",tags:["Biochimie","Amylase","Lipase","Pancréas"]},
  {id:"abm_bc14",prompt:"Le dosage de la ferritine reflète :",choices:["La quantité de fer circulant","Les réserves en fer de l'organisme (stockage intracellulaire)","La synthèse de l'hémoglobine","L'absorption intestinale du fer"],answer:1,diff:2,explication:"Ferritine = protéine de stockage intracellulaire du fer. < 12 µg/L = déplétion des réserves (carence martiale certaine). Élevée = surcharge (hémochromatose) ou syndrome inflammatoire (réactant phase aiguë).",tags:["Biochimie","Ferritine","Fer","Bilan martial"]},
  {id:"abm_bc15",prompt:"L'urée sérique est augmentée en cas de :",choices:["Hépatopathie sévère uniquement","Insuffisance rénale, déshydratation, hypercatabolisme protéique","Carence en protéines alimentaires","Diabète sucré isolé"],answer:1,diff:2,explication:"Urée = déchet catabolisme protéique, synthétisée dans le foie, éliminée par le rein. ↑ insuffisance rénale, déshydratation, régime hyperprotéique. ↓ hépatopathie sévère (↓ synthèse).",tags:["Biochimie","Urée","Rein","Azote"]},
];

export const QB_ABM_MICRO_MED = [
  {id:"abm_mm1",prompt:"Le seuil de significativité d'une leucocyturie (ECBU) est :",choices:["100 leucocytes/µL","≥ 10 leucocytes/µL (ou 10 000/mL)","1 leucocyte/µL","5 leucocytes/µL"],answer:1,diff:1,explication:"ECBU : leucocyturie ≥ 10⁴/mL (10/µL) = significative. Bactériurie ≥ 10⁵ UFC/mL pour E. coli. Seuils variables selon contexte clinique et espèce.",tags:["Microbiologie médicale","ECBU","Leucocyturie"]},
  {id:"abm_mm2",prompt:"L'agent causal le plus fréquent des infections urinaires communautaires est :",choices:["Staphylococcus aureus","Escherichia coli (80% des cas)","Pseudomonas aeruginosa","Enterococcus faecalis"],answer:1,diff:1,explication:"E. coli = 80% des IU communautaires. Klebsiella pneumoniae 2ème. Proteus mirabilis 3ème. Staphylococcus saprophyticus chez la jeune femme.",tags:["Microbiologie médicale","ECBU","E. coli","IU"]},
  {id:"abm_mm3",prompt:"Les hémocultures doivent être prélevées :",choices:["Après antibiothérapie","Avant antibiothérapie, au pic fébrile, par 2-3 paires (sites différents)","Une seule fois","Uniquement sur tube EDTA"],answer:1,diff:2,explication:"Hémocultures : avant toute antibiothérapie (si possible), idéalement au frisson/pic fébrile. Minimum 2-3 paires à des sites différents (augmente sensibilité à 80-90%). Volumes : 8-10 mL/flacon adulte.",tags:["Microbiologie médicale","Hémocultures","Bactériémie"]},
  {id:"abm_mm4",prompt:"Le milieu CLED (Cystine Lactose Electrolyte Deficient) est utilisé pour :",choices:["L'isolement de Mycobacterium tuberculosis","L'ECBU (détection colorimétrique E. coli et non-fermentants)","La recherche de Salmonella","La culture des champignons"],answer:1,diff:2,explication:"CLED : milieu spécifique ECBU. Entérobactéries : colonies jaunes (fermentent lactose). Non-fermentants (Pseudomonas) : bleues. E. coli : jaune foncé avec halo de couleur.",tags:["Microbiologie médicale","ECBU","Milieux","CLED"]},
  {id:"abm_mm5",prompt:"La sensibilité aux antibiotiques d'une bactérie (S, I, R) est déterminée selon :",choices:["Le Gram uniquement","Les diamètres d'inhibition de la croissance autour des disques (méthode de diffusion) comparés aux valeurs critiques EUCAST","La morphologie coloniale","La vitesse de croissance"],answer:1,diff:2,explication:"Antibiogramme : méthode disque-diffusion (Kirby-Bauer) sur gélose Mueller-Hinton. Lecture diamètre inhibition → interprétation S/I/R selon tables EUCAST (normes européennes).",tags:["Microbiologie médicale","Antibiogramme","EUCAST","Résistances"]},
  {id:"abm_mm6",prompt:"Un BLSE (Beta-Lactamase à Spectre Étendu) confère une résistance à :",choices:["Uniquement à l'amoxicilline","Aux céphalosporines de 3e génération, pénicillines et monobactames","Aux carbapénèmes","Aux aminosides uniquement"],answer:1,diff:3,explication:"BLSE hydrolyse pénicillines, C1-C4G, monobactames (aztréonam). Inhibés par inhibiteurs β-lactamases (acide clavulanique). Carbapénèmes actifs. Dépistage par synergie amoxicilline-clavulanate + C3G.",tags:["Microbiologie médicale","BLSE","Résistances","Antibiotiques"]},
  {id:"abm_mm7",prompt:"Staphylococcus aureus résistant à la méticilline (SARM) est détecté par :",choices:["Antibiogramme classique uniquement","Test de la céfoxitine (disque 30µg) ou PCR mecA","Test d'oxydase","Coloration de Gram"],answer:1,diff:2,explication:"SARM : gène mecA code PLP2a (faible affinité β-lactamines). Dépistage : disque céfoxitine 30µg (zone < 22 mm = résistant). Confirmation : PCR mecA. Isolement contact obligatoire.",tags:["Microbiologie médicale","SARM","Résistances","Staphylocoque"]},
  {id:"abm_mm8",prompt:"La coproculture standard recherche en priorité :",choices:["E. coli pathogène, Salmonella, Shigella, Campylobacter","Staphylococcus aureus uniquement","Pseudomonas aeruginosa","Candida albicans"],answer:0,diff:2,explication:"Coproculture standard : recherche Salmonella, Shigella, Campylobacter (milieux sélectifs spécifiques). E. coli entéropathogènes si nourrisson. Milieux : Hektoen (Salmonella/Shigella), Karmali (Campylobacter, 42°C).",tags:["Microbiologie médicale","Coproculture","Entéropathogènes"]},
  {id:"abm_mm9",prompt:"Le milieu de Chapman (milieu hypersalé + mannitol) est sélectif pour :",choices:["Les entérobactéries","Les staphylocoques (résistance au NaCl)","Les streptocoques","Les bacilles Gram-"],answer:1,diff:2,explication:"Chapman : 7.5% NaCl (inhibe la plupart des bactéries sauf staphylocoques). Mannitol fermenté par S. aureus → coloration jaune. S. epidermidis : mannitol négatif → colonies rose/rouge.",tags:["Microbiologie médicale","Milieux","Staphylocoques","Chapman"]},
  {id:"abm_mm10",prompt:"Le diagnostic biologique de la tuberculose repose sur :",choices:["Uniquement la radiographie","Examen direct (BAAR au Ziehl-Neelsen ou fluorescence) + culture sur Löwenstein-Jensen (6-8 semaines)","Uniquement la sérologie","Le test de Mantoux seul"],answer:1,diff:2,explication:"BK : bacille acido-alcoolo-résistant (BAAR). Ziehl-Neelsen (rouge) ou fluorescence (auramine). Culture LJ : 3-8 semaines. PCR/GeneXpert : résultat rapide + détection résistance rifampicine.",tags:["Microbiologie médicale","Tuberculose","BK","Ziehl"]},
  {id:"abm_mm11",prompt:"Streptococcus pyogenes (groupe A) est diagnostiqué rapidement par :",choices:["Culture sur gélose BCYE","Test de diagnostic rapide (TDR) streptococcique ou culture sur gélose au sang","Milieu MacConkey","Galerie API Gram-"],answer:1,diff:1,explication:"Strep A : TDR (détection Ag polysaccharidique en 5 min, Sp > 95%). Culture gélose sang : hémolyse β. Sensibilité pénicilline G toujours conservée (jamais de résistance acquise).",tags:["Microbiologie médicale","Streptocoque","TDR","Angine"]},
  {id:"abm_mm12",prompt:"Neisseria gonorrhoeae est un diplocoque Gram :",choices:["Positif, en chaînes","Négatif, intracellulaire en grain de café","Positif, en grappes","Négatif, mobile à péritriches"],answer:1,diff:2,explication:"Gonocoque : diplocoques Gram- intracellulaires en 'grain de café', dans PNN. Milieux sélectifs (Thayer-Martin + CO₂). Résistances croissantes aux fluoroquinolones et céphalosporines.",tags:["Microbiologie médicale","Gonocoque","IST","Gram-"]},
  {id:"abm_mm13",prompt:"La détection des antigènes urinaires de Legionella pneumophila (sérogroupe 1) a une sensibilité de :",choices:["20-30%","70-90%","< 10%","100%"],answer:1,diff:2,explication:"Ag urinaires Legionella sg1 : sensibilité 70-90%, spécificité >99%. Résultat en 15 min. Ne détecte que sg1 (80% des cas). Confirmer par culture ou PCR pour les autres sérogroupes.",tags:["Microbiologie médicale","Legionella","Antigènes urinaires","Pneumonie"]},
  {id:"abm_mm14",prompt:"Le milieu de référence pour les hémocultures en aérobiose utilise :",choices:["Un milieu solide gélosé","Un milieu liquide enrichi + résines/charbon adsorbant les antibiotiques","Une cuve d'anaérobiose","Du milieu Sabouraud"],answer:1,diff:2,explication:"Flacons hémocultures (aérobie/anaérobie) : milieu liquide enrichi (peptones, glucose, compléments) + activateurs de croissance + résines adsorbant les antibiotiques. Lecture automatisée (BACTEC, VITEK).",tags:["Microbiologie médicale","Hémocultures","Milieux","Automates"]},
  {id:"abm_mm15",prompt:"L'examen direct d'un LCR (liquide céphalo-rachidien) trouble doit être réalisé :",choices:["Dans les 48 heures","En urgence absolue (< 30 min), sans délai","Après centrifugation uniquement","Après culture de 24h"],answer:1,diff:1,explication:"LCR trouble = méningite purulente probable → urgence vitale. Examen direct (Gram + numération cellules) immédiat. Antibiothérapie débutée sans attendre la culture si contexte clinique évocateur.",tags:["Microbiologie médicale","LCR","Méningite","Urgence"]},
];

export const QB_ABM_IMMUNO = [
  {id:"abm_im1",prompt:"Le diagnostic biologique du VIH repose sur :",choices:["La numération des CD4 uniquement","Le test ELISA de dépistage (Ac + Ag p24) confirmé par Western blot ou Immunoblot","La PCR ARN viral seule","La charge virale seule"],answer:1,diff:2,explication:"VIH : ELISA 4e génération (Ac anti-VIH + Ag p24 combinés). Si positif : Western blot de confirmation. Charge virale ARN + CD4 pour le suivi. Délai fenêtre : 6 semaines.",tags:["Immunologie","VIH","ELISA","Sérologie"]},
  {id:"abm_im2",prompt:"La sérologie hépatite B : un profil VHB (Ag HBs +, Ac anti-HBs -, Ac anti-HBc +) signifie :",choices:["Infection ancienne guérie","Infection aiguë ou chronique active (portage de l'Ag HBs)","Vaccination efficace","Immunité naturelle"],answer:1,diff:3,explication:"Ag HBs+ = porteur du VHB. Anti-HBs- = pas d'immunité. Anti-HBc+ = contact avec le virus. Profil d'infection aiguë (si IgM anti-HBc +) ou chronique (IgG anti-HBc +).",tags:["Immunologie","Hépatite B","VHB","Sérologie"]},
  {id:"abm_im3",prompt:"La sérologie toxoplasmose chez la femme enceinte : IgG+, IgM- signifie :",choices:["Primo-infection en cours","Immunité ancienne (infection antérieure guérie, pas de risque pour le fœtus)","Absence totale d'immunité","Infection congénitale"],answer:1,diff:2,explication:"IgG+ IgM- = infection ancienne, immunité acquise. Pas de surveillance supplémentaire nécessaire. IgG- IgM- = séronégative → surveillance mensuelle. IgM+ → datation de l'infection.",tags:["Immunologie","Toxoplasmose","Grossesse","Sérologie"]},
  {id:"abm_im4",prompt:"Le facteur rhumatoïde (FR) est un :",choices:["Anticorps anti-ADN","Auto-anticorps (IgM anti-IgG) associé à la polyarthrite rhumatoïde","Complément activé","Cytokine pro-inflammatoire"],answer:1,diff:2,explication:"FR = IgM dirigées contre la fraction Fc des IgG. Présent dans 70-80% des PR. Peu spécifique (aussi dans lupus, syndrome de Gougerot-Sjögren, hépatopathies). Les anti-CCP sont plus spécifiques.",tags:["Immunologie","Facteur rhumatoïde","Auto-anticorps","PR"]},
  {id:"abm_im5",prompt:"Les anticorps anti-nucléaires (AAN) sont le marqueur de dépistage du :",choices:["Syndrome de l'intestin irritable","Lupus érythémateux systémique (LES)","Diabète type 1","Maladie de Crohn"],answer:1,diff:1,explication:"AAN (immunofluorescence indirecte sur cellules HEp-2) : sensibilité > 95% pour LES. Si positif, compléter par anti-ADN natifs (spécifiques LES) et anti-ENA (Sm, SSA, SSB, SCL70, Jo1...).",tags:["Immunologie","AAN","Lupus","Auto-anticorps"]},
  {id:"abm_im6",prompt:"Le test de Coombs direct (test à l'antiglobuline direct) recherche :",choices:["Des anticorps libres dans le sérum","Des anticorps ou du complément fixés directement sur les érythrocytes","L'incompatibilité ABO","La fertilité masculine"],answer:1,diff:2,explication:"Coombs direct : antiglobuline (anti-IgG + anti-C3d) ajoutée directement aux GR du patient. Positif dans anémies hémolytiques auto-immunes, MHNN, réactions transfusionnelles.",tags:["Immunologie","Coombs","Anémie hémolytique","Immunohématologie"]},
  {id:"abm_im7",prompt:"La détermination du groupe sanguin ABO-RH1 nécessite :",choices:["Une seule technique","Deux techniques concordantes obligatoires (Beth-Vincent + Simonin pour ABO, 2 réactifs pour RH1)","Uniquement la technique sérique","Uniquement la technique globulaire"],answer:1,diff:2,explication:"Sécurité transfusionnelle : ABO = Beth-Vincent (globules-test) + Simonin (sérum-test) concordants. RH1 (D) = 2 réactifs monoclonaux concordants. Résultats discordants → investigation obligatoire.",tags:["Immunologie","Groupe sanguin","ABO","Transfusion"]},
  {id:"abm_im8",prompt:"La RAI (Recherche d'Anticorps Irréguliers) est obligatoire :",choices:["Uniquement avant une première transfusion","Avant toute transfusion (< 72h avant), en grossesse (28 SA, accouchement)","Uniquement lors d'une grossesse","Une fois dans la vie"],answer:1,diff:2,explication:"RAI valable 72h en contexte transfusionnel. Obligatoire à 28 SA et avant l'accouchement. Dépiste Ac anti-érythrocytaires (anti-Kell, anti-Duffy, anti-Kidd...) qui peuvent causer hémolyse ou MHNN.",tags:["Immunologie","RAI","Transfusion","Grossesse"]},
  {id:"abm_im9",prompt:"La procalcitonine (PCT) est utilisée pour distinguer :",choices:["Grippe et angine bactérienne","Infection bactérienne sévère (sepsis) vs inflammation non infectieuse","Diabète type 1 et type 2","Anémie carentielle et anémie inflammatoire"],answer:1,diff:2,explication:"PCT très élevée (> 2 µg/L) = probable infection bactérienne sévère/sepsis. < 0.5 µg/L = contre-indication antibiothérapie (infection virale ou non infectieuse probable). Outil de désescalade.",tags:["Immunologie","Procalcitonine","Sepsis","Infection"]},
  {id:"abm_im10",prompt:"Les IgE spécifiques sont dosées pour :",choices:["Dépister le VIH","Identifier les allergènes responsables d'allergie IgE-médiée","Diagnostiquer une infection bactérienne","Surveiller une greffe"],answer:1,diff:1,explication:"IgE spécifiques : dosage Ac IgE dirigés contre un allergène précis (arachide, acarien, latex...). Complète le bilan allergologique. IgE totales peu spécifiques. Prick-tests = test in vivo de référence.",tags:["Immunologie","IgE","Allergie","Atopie"]},
];

export const QB_ABM_PARASITO = [
  {id:"abm_pm1",prompt:"L'examen parasitologique des selles (EPS) comprend :",choices:["Uniquement la recherche d'amibes","Examen direct (état frais), technique de concentration (Ritchie ou Bailenger) et coloration (Ziehl ou Trichrome)","Uniquement la culture","Uniquement la sérologie"],answer:1,diff:2,explication:"EPS complet : examen macroscopique (aspect, parasites visibles), microscopique (état frais : mobilité, formes végétatives), concentration (enrichit les parasites), coloration. 3 selles sur 3 jours différents recommandé.",tags:["Parasitologie","EPS","Selles","Technique"]},
  {id:"abm_pm2",prompt:"La goutte épaisse et le frottis mince (colorés au Giemsa) servent à diagnostiquer :",choices:["La toxoplasmose","Le paludisme (Plasmodium spp) et autres parasites sanguins","La giardiose","Les oxyures"],answer:1,diff:1,explication:"Goutte épaisse : concentration maximale (détection de faible parasitémie). Frottis mince : identification de l'espèce (morphologie GR parasités, schüffner, aspect parasite). Résultat en urgence (< 2h).",tags:["Parasitologie","Paludisme","Plasmodium","Frottis"]},
  {id:"abm_pm3",prompt:"Plasmodium falciparum est l'espèce la plus grave car :",choices:["Elle est la plus commune en France","Elle peut provoquer un neuropaludisme (trophozoïtes dans microcirculation cérébrale) et a développé des résistances","Elle est la plus facile à traiter","Elle ne donne que des accès simples"],answer:1,diff:2,explication:"P. falciparum : rosace (schizonte) dans les organes profonds (non visible sur frottis). Cytoadhérence → occlusion microvasculaire cérébrale (neuropaludisme). Résistances chloroquine très répandues.",tags:["Parasitologie","Paludisme","P. falciparum","Urgence"]},
  {id:"abm_pm4",prompt:"Le test de diagnostic rapide (TDR) du paludisme détecte :",choices:["Les Ac antipaludéens","Les Ag parasitaires (HRP2 pour P. falciparum, LDH panaspecifique) en 15 min","La parasitémie exacte","Les résistances aux antipaludéens"],answer:1,diff:2,explication:"TDR paludisme : bandelette immunochromatographique. HRP2 (Histidine Rich Protein 2) = spécifique P. falciparum. pLDH = pan-spécifique (toutes espèces). Sensibilité > 95% si parasitémie > 100/µL. Complémentaire du frottis.",tags:["Parasitologie","Paludisme","TDR","Diagnostic rapide"]},
  {id:"abm_pm5",prompt:"Entamoeba histolytica se distingue de E. dispar par :",choices:["Sa morphologie uniquement","Sa pathogénicité (E. histolytica provoque l'amibiase invasive, E. dispar est non pathogène)","Sa localisation géographique uniquement","Sa taille uniquement"],answer:1,diff:2,explication:"E. histolytica et E. dispar sont morphologiquement identiques (PCR nécessaire). E. histolytica : amibiase intestinale aiguë (rectorragies), abcès amibien du foie. E. dispar : non pathogène, pas de traitement.",tags:["Parasitologie","Amibiase","Entamoeba","Dysenterie"]},
  {id:"abm_pm6",prompt:"Giardia intestinalis (lamblia) provoque principalement :",choices:["Une amibiase hépatique","Une giardiose : diarrhée chronique, malabsorption (stéatorrhée), localisation duodéno-jéjunale","Un neuropaludisme","Une toxoplasmose intestinale"],answer:1,diff:2,explication:"Giardia : protozoaire flagellé, kystes dans l'eau. Formes végétatives en ventouse sur entérocytes duodénaux → malabsorption des graisses, vitamines liposolubles. Diagnostic : EPS (kystes) ou Ag fécaux. Traitement : métronidazole.",tags:["Parasitologie","Giardiose","Giardia","Protozoaire"]},
  {id:"abm_pm7",prompt:"Cryptosporidium parvum est un parasite particulièrement dangereux chez :",choices:["Les adultes immunocompétents","Les patients immunodéprimés (VIH, greffe) et les nourrissons (diarrhée sévère et prolongée)","Les personnes âgées uniquement","Les hommes uniquement"],answer:1,diff:2,explication:"Cryptosporidiose : oocystes très résistants (même chlore). Immunocompétents : diarrhée auto-limitante (1-2 sem). Immunodéprimés (VIH CD4<200) : diarrhée chronique sévère, déshydratation grave. Diagnostic : Ziehl modifié sur selles.",tags:["Parasitologie","Cryptosporidium","Immunodéprimé","VIH"]},
  {id:"abm_pm8",prompt:"La coloration de Ziehl-Neelsen modifiée (Ziehl à froid) permet de mettre en évidence :",choices:["Les bactéries à Gram positif","Les parasites acido-alcoolo-résistants : Cryptosporidium, Isospora, Cyclospora, et les mycobactéries","Les champignons uniquement","Les helminthes"],answer:1,diff:2,explication:"Ziehl à froid (en différence du Ziehl chaud pour BK) : colore en rouge les organismes acido-résistants (Cryptosporidium oocystes = petits cercles roses). Fond bleu au bleu de méthylène.",tags:["Parasitologie","Ziehl modifié","Cryptosporidium","Colorations"]},
  {id:"abm_pm9",prompt:"Candida albicans produit un test de filamentation positif car :",choices:["Il forme des arthrospores à 37°C","Il forme des tubes germinatifs (pseudomycélium + blastospores) à 37°C en 2h dans sérum","Il colore en bleu au Gram","Il pousse uniquement à 25°C"],answer:1,diff:2,explication:"Test de filamentation (tube germinal) : C. albicans incubé dans sérum à 37°C → tubes germinatifs en 2h. Caractère diagnostique de C. albicans et C. dubliniensis. Autres Candida : négatif.",tags:["Mycologie","Candida","Test de filamentation","Identification"]},
  {id:"abm_pm10",prompt:"Le milieu de Sabouraud est utilisé pour la culture des champignons car :",choices:["Il contient des antibactériens et favorise la croissance des champignons (pH acide, glucose)","Il est à pH neutre","Il contient du sang","Il permet la culture des mycobactéries"],answer:0,diff:1,explication:"Milieu Sabouraud : glucose 4%, peptones, pH 5.5-6.5 (inhibe bactéries) + chloramphénicol/gentamicine (anti-bactérien). 25°C (levures + dermatophytes) et 37°C (levures uniquement). Base de la mycologie.",tags:["Mycologie","Sabouraud","Culture","Champignons"]},
  {id:"abm_pm11",prompt:"Les dermatophytes (Trichophyton, Epidermophyton, Microsporum) provoquent des infections :",choices:["Viscérales profondes","Cutanées superficielles kératinophiles (tineas : pied d'athlète, onychomycose, teigne)","Systémiques sévères uniquement","Pulmonaires principalement"],answer:1,diff:1,explication:"Dermatophytes : kératinophiles et kératinolytiques. Trichophyton rubrum : pied d'athlète, onychomycose (90%). T. violaceum : teigne du cuir chevelu. Culture sur Sabouraud 25°C + DTM (milieu différentiel).",tags:["Mycologie","Dermatophytes","Tinea","Kératinophile"]},
  {id:"abm_pm12",prompt:"Aspergillus fumigatus peut provoquer chez les patients greffés ou sous corticoïdes :",choices:["Une simple rhinite","Une aspergillose invasive (angio-invasive) pulmonaire avec mortalité élevée","Une infection cutanée superficielle uniquement","Une méningite virale"],answer:1,diff:2,explication:"Aspergillus : champignon filamenteux ubiquitaire. Immunocompétents : sinusite ou aspergillose pulmonaire allergique. Immunodéprimés : aspergillose invasive angio-invasive (corrigée par voriconazole). Diagnostic : galactomannane sérique + TDM thorax.",tags:["Mycologie","Aspergillus","Aspergillose invasive","Immunodéprimé"]},
  {id:"abm_pm13",prompt:"La sérologie toxoplasmose en IgG avidité est indiquée :",choices:["Pour toutes les femmes enceintes","En cas d'IgM positive pour dater la primo-infection (avidité faible = infection récente < 4 mois)","Pour le diagnostic du paludisme","Pour la surveillance des patients VIH"],answer:1,diff:3,explication:"Avidité des IgG : liaison fonctionnelle Ac-Ag. Faible avidité (< 30%) = primo-infection < 4 mois (Ac peu matures). Forte avidité (> 65%) = infection > 4 mois (rassure). Aide à dater une IgM+ pour décision thérapeutique.",tags:["Parasitologie","Toxoplasmose","Avidité","Grossesse"]},
  {id:"abm_pm14",prompt:"L'oxyurose (Enterobius vermicularis) se diagnostique par :",choices:["EPS standard","Test de Graham (scotch-test anal : les oxyures pondent leurs œufs en périanal)","Sérologie","Frottis sanguin"],answer:1,diff:2,explication:"Oxyures : helminthes intestinaux très communs chez l'enfant. Oviposition péri-anale nocturne → prurit anal. Diagnostic : test de Graham (Scotch-test) le matin avant la toilette. EPS souvent négatif (peu d'œufs dans les selles).",tags:["Parasitologie","Oxyures","Test de Graham","Helminthes"]},
  {id:"abm_pm15",prompt:"Trichomonas vaginalis est un protozoaire flagellé transmis par :",choices:["La voie oro-fécale","Voie sexuelle — infection sexuellement transmissible (IST) fréquente","Les moustiques","L'eau contaminée"],answer:1,diff:1,explication:"T. vaginalis : IST protozoaire la plus fréquente. Femme : vaginite (pertes jaunes, prurit). Homme : souvent asymptomatique. Diagnostic : examen direct à frais (mobilité) ou PCR. Traitement : métronidazole (couple).",tags:["Parasitologie","Trichomonas","IST","Vaginite"]},
];

export const QB_ABM_BIO_MOL = [
  {id:"abm_bm1",prompt:"La PCR (Polymerase Chain Reaction) a été inventée par :",choices:["Louis Pasteur en 1865","Kary Mullis en 1985 (Prix Nobel de chimie 1993)","Watson et Crick en 1953","Frederick Sanger en 1977"],answer:1,diff:1,explication:"Kary Mullis (Cetus Corporation) invente la PCR en 1985. Prix Nobel de chimie 1993. Cette technique d'amplification enzymatique in vitro révolutionne la biologie moléculaire.",tags:["Biologie moléculaire","PCR","Histoire"]},
  {id:"abm_bm2",prompt:"L'étape de dénaturation de la PCR se réalise à :",choices:["37°C","50-65°C","72°C","90-95°C"],answer:3,diff:1,explication:"Dénaturation : 90-95°C, 30s à 1 min. La chaleur rompt les liaisons hydrogène entre les bases azotées, séparant l'ADN double brin en deux brins simples (mimétisme de l'hélicase in vivo).",tags:["Biologie moléculaire","PCR","Dénaturation"]},
  {id:"abm_bm3",prompt:"L'étape d'hybridation (appariement des amorces) de la PCR se réalise à :",choices:["90-95°C","50-65°C","72°C","25°C"],answer:1,diff:1,explication:"Hybridation/Annealing : 50-65°C. Les amorces (oligonucléotides synthétiques) reconnaissent leur séquence complémentaire et s'hybrident sur les brins simples d'ADN. Température spécifique à chaque couple d'amorces.",tags:["Biologie moléculaire","PCR","Hybridation","Amorces"]},
  {id:"abm_bm4",prompt:"L'étape d'élongation de la PCR (synthèse du brin complémentaire) se réalise à :",choices:["95°C","50-65°C","72°C","37°C"],answer:2,diff:1,explication:"Élongation : 72°C = température optimale de la Taq polymérase (ADN polymérase thermorésistante). Elle synthétise le brin complémentaire en incorporant les dNTPs dans le sens 5'→3'.",tags:["Biologie moléculaire","PCR","Élongation","Taq polymérase"]},
  {id:"abm_bm5",prompt:"La Taq polymérase est utilisée en PCR car :",choices:["Elle est plus rapide que les autres polymérases","Elle est thermorésistante (active à 95°C) et résiste aux cycles de dénaturation thermique","Elle peut amplifier l'ARN directement","Elle ne nécessite pas d'amorces"],answer:1,diff:2,explication:"Taq polymérase (Thermus aquaticus) : ADN polymérase stable jusqu'à 95°C. Avant la Taq, la polymérase était dénaturée à chaque cycle et devait être réajoutée manuellement. La Taq a rendu la PCR automatisable.",tags:["Biologie moléculaire","PCR","Taq polymérase","Thermorésistance"]},
  {id:"abm_bm6",prompt:"Les 6 réactifs essentiels d'une réaction PCR sont :",choices:["ADN, amorces, eau","ADN matrice, amorces sens/anti-sens, Taq polymérase, dNTPs (A,T,G,C), tampon, MgCl₂","ADN matrice et Taq polymérase uniquement","Amorces, acide phosphorique, ATP"],answer:1,diff:2,explication:"Mix PCR : 1) ADN matrice (cible), 2) Amorce sens + amorce anti-sens (flanquent la région cible), 3) Taq polymérase, 4) dNTPs (désoxyribonucléotides : dATP, dTTP, dGTP, dCTP), 5) tampon (pH optimal), 6) MgCl₂ (cofacteur Taq).",tags:["Biologie moléculaire","PCR","Réactifs","Mix PCR"]},
  {id:"abm_bm7",prompt:"Combien de cycles sont généralement réalisés dans une PCR standard ?",choices:["5 à 10 cycles","20 à 35 cycles (environ 30 en standard)","50 à 100 cycles","1 à 3 cycles"],answer:1,diff:1,explication:"PCR standard : 25-35 cycles (30 en général). À chaque cycle, l'ADN double exponentiellement : après 30 cycles → 2³⁰ ≈ 10⁹ copies d'une copie initiale. Au-delà de 35 cycles : risque d'amplification non spécifique.",tags:["Biologie moléculaire","PCR","Cycles","Amplification"]},
  {id:"abm_bm8",prompt:"La PCR multiplex permet de :",choices:["Amplifier un seul fragment très long","Détecter simultanément plusieurs cibles différentes en utilisant plusieurs paires d'amorces","Quantifier l'ADN en temps réel","Séquencer l'ADN directement"],answer:1,diff:2,explication:"PCR multiplex : plusieurs paires d'amorces dans le même tube → amplification simultanée de plusieurs régions cibles. Applications : panel respiratoire (grippe A/B, SARS-CoV-2, RSV), panel IST, identification bactérienne.",tags:["Biologie moléculaire","PCR multiplex","Applications cliniques"]},
  {id:"abm_bm9",prompt:"La différence entre ADN et ARN concerne notamment le sucre : l'ADN contient du :",choices:["Ribose","Désoxyribose (manque un groupement OH en position 2')","Fructose","Galactose"],answer:1,diff:1,explication:"ADN : désoxyribose (β-D-2-désoxy-ribofuranose). ARN : ribose. La différence est un groupement OH en position 2' du ribose. Conséquence : l'ARN est moins stable (susceptible à l'hydrolyse alcaline).",tags:["Biologie moléculaire","ADN","ARN","Pentose"]},
  {id:"abm_bm10",prompt:"La base thymine (T) est présente :",choices:["Dans l'ADN ET l'ARN","Uniquement dans l'ADN (dans l'ARN elle est remplacée par l'uracile)","Uniquement dans l'ARN","Dans ni l'ADN ni l'ARN"],answer:1,diff:1,explication:"Thymine : base pyrimidique de l'ADN uniquement. Dans l'ARN, la thymine est remplacée par l'uracile (U). Cytosine (C) et bases puriques (A, G) sont communes aux deux. ADN : A, T, G, C. ARN : A, U, G, C.",tags:["Biologie moléculaire","ADN","ARN","Bases azotées","Thymine"]},
  {id:"abm_bm11",prompt:"Les trois types d'ARN cellulaires sont :",choices:["ARN viral, ARN bactérien, ARN cellulaire","ARN messager (ARNm), ARN de transfert (ARNt), ARN ribosomique (ARNr)","ARN sens, ARN antisens, ARN double brin","ARN court, ARN long, ARN circulaire"],answer:1,diff:1,explication:"ARNm : copie de l'ADN codant, traduit en protéine. ARNt : adapter (anticodon ↔ codon, transport des acides aminés). ARNr : composant structural des ribosomes (28S, 18S, 5.8S, 5S chez eucaryotes).",tags:["Biologie moléculaire","ARN","ARNm","ARNt","ARNr"]},
  {id:"abm_bm12",prompt:"Le séquençage de Sanger (méthode des didésoxynucléotides) est la méthode :",choices:["De PCR multiplex","De référence pour le séquençage de fragments (200-1000 pb) — base des séquençages avant le NGS","D'électrophorèse capillaire uniquement","D'amplification ARN"],answer:1,diff:2,explication:"Sanger (1977, Prix Nobel) : ddNTPs (didésoxynucléotides) bloquent l'élongation aléatoirement. Fragments de tailles différentes séparés par électrophorèse capillaire → séquence lue. Standard pour petits fragments. NGS = haut débit.",tags:["Biologie moléculaire","Séquençage","Sanger","NGS"]},
  {id:"abm_bm13",prompt:"L'électrophorèse sur gel d'agarose après PCR sépare les fragments d'ADN selon :",choices:["Leur charge électrique uniquement","Leur taille (en paires de bases) : les petits fragments migrent plus vite vers l'anode","Leur composition en bases","Leur double brin vs simple brin uniquement"],answer:1,diff:2,explication:"Gel agarose + tampon TBE/TAE. ADN chargé négativement migre vers l'anode (+). Migration inversement proportionnelle à la taille. Marqueur de taille (ladder) comme référence. Révélation : BET (bromure d'éthidium) ou SYBR Safe sous UV.",tags:["Biologie moléculaire","Électrophorèse","Gel agarose","PCR"]},
  {id:"abm_bm14",prompt:"La PCR quantitative en temps réel (qPCR) mesure :",choices:["Uniquement la présence/absence d'un gène","L'accumulation de produit PCR cycle par cycle (fluorescence) → quantification de la charge virale ou expression génique","La séquence exacte de l'ADN","La taille des fragments amplifiés uniquement"],answer:1,diff:2,explication:"qPCR (temps réel) : fluorescence (SybrGreen intercalant, ou sonde TaqMan spécifique) mesurée après chaque cycle. Ct (cycle seuil) inversement proportionnel à la quantité initiale. Applications : charges virales (VIH, VHC, CMV), résidus maladie (BCR-ABL).",tags:["Biologie moléculaire","qPCR","Temps réel","Charge virale"]},
  {id:"abm_bm15",prompt:"La RT-PCR (Reverse Transcription PCR) est utilisée pour :",choices:["Amplifier l'ADN génomique directement","Amplifier l'ARN (après reverse transcription en ADNc par la rétrotranscriptase)","Séquencer l'ADN","Analyser les protéines"],answer:1,diff:2,explication:"RT-PCR : rétrotranscriptase (reverse transcriptase) convertit l'ARN en ADN complémentaire (ADNc), puis PCR classique sur l'ADNc. Applications : ARN viral (VIH, HCV), expression génique (ARNm), diagnostic COVID-19.",tags:["Biologie moléculaire","RT-PCR","Rétrotranscriptase","ARN"]},
];

export const QB_ABM_BACTERIO_STRUCT = [
  {id:"abm_bs1",prompt:"Les bactéries sont définies comme des organismes :",choices:["Eucaryotes avec un vrai noyau","Procaryotes : pas de noyau membranaire, ADN chromosomique circulaire dans le cytoplasme","Virus intracellulaires obligatoires","Champignons unicellulaires"],answer:1,diff:1,explication:"Procaryotes : pas de membrane nucléaire. L'ADN chromosomique (circulaire) flotte dans le cytoplasme (nucléoïde). Ribosomes 70S (vs 80S chez eucaryotes). Paroi + membrane cytoplasmique.",tags:["Bactériologie","Structure bactérienne","Procaryote"]},
  {id:"abm_bs2",prompt:"La taille habituelle d'une bactérie est de :",choices:["10 à 50 µm","0.5 à 1 µm de diamètre × 2 à 5 µm de long","0.001 µm (nanomètre)","100 à 200 µm"],answer:1,diff:1,explication:"Bactéries : 0.5-1 µm de diamètre, 2-5 µm de long. Mycoplasmes (sans paroi) : les plus petites (0.1-0.3 µm). Les champignons sont 10-100x plus grands. Parasites macroscopiques = visibles à l'œil nu.",tags:["Bactériologie","Taille","Morphologie"]},
  {id:"abm_bs3",prompt:"La coloration de Gram différencie les bactéries en :",choices:["Aérobies vs anaérobies","Gram+ (violet, paroi épaisse en peptidoglycane) et Gram- (rose, paroi mince + membrane externe LPS)","Mobiles vs immobiles","Sporulantes vs non-sporulantes"],answer:1,diff:1,explication:"Gram+ : peptidoglycane épais → retient cristal violet → violet. Gram- : paroi mince + membrane externe (LPS endotoxine) → ne retient pas → rose après safranine. Principe : décoloration à l'alcool-acétone.",tags:["Bactériologie","Coloration de Gram","Paroi","Peptidoglycane"]},
  {id:"abm_bs4",prompt:"La capsule bactérienne (structure facultative) confère à la bactérie :",choices:["La mobilité","Une résistance à la phagocytose (facteur de virulence majeur) et à la dessiccation","La synthèse de toxines","La résistance aux antibiotiques bêta-lactamines"],answer:1,diff:2,explication:"Capsule (polysaccharide ou polyprotéine) : anti-phagocytaire (facteur de virulence important). Streptococcus pneumoniae, Haemophilus influenzae, Klebsiella : capsule = pathogénicité. Aussi : résistance à la dessiccation et adhésion.",tags:["Bactériologie","Capsule","Virulence","Phagocytose"]},
  {id:"abm_bs5",prompt:"Les plasmides bactériens sont des :",choices:["Fragments de l'ADN chromosomique","ADN extra-chromosomiques circulaires (facultatifs) portant des gènes de résistance ou de virulence","Éléments de la membrane externe","Organites de la synthèse protéique"],answer:1,diff:2,explication:"Plasmides : ADN circulaire extra-chromosomique, réplication autonome. Portent : gènes résistance antibiotiques (R-plasmides), toxines, facteurs de virulence. Transférables par conjugaison (transfert horizontal).",tags:["Bactériologie","Plasmides","Résistances","Gènes"]},
  {id:"abm_bs6",prompt:"Les flagelles bactériaux confèrent à la bactérie :",choices:["La résistance aux antibiotiques","La mobilité (ciliature polaire = rapide/linéaire ; péritrique = lente/sinueuse)","La formation de biofilm","La sporulation"],answer:1,diff:1,explication:"Flagelles : appendices filamenteux protéiques (flagelline). Ciliature polaire (Pseudomonas, Vibrio) : flagelle à un pôle → mouvement rapide et linéaire. Péritrique (Enterobactéries, Clostridium) : flagelles tout autour → mouvement lent et sinueux.",tags:["Bactériologie","Flagelles","Mobilité","Ciliature"]},
  {id:"abm_bs7",prompt:"Pour orienter l'identification d'une bactérie Gram-, le premier test réalisé est :",choices:["Le test catalase","Le test oxydase (différencie entérobactéries des non-fermentants)","L'antibiogramme","La culture sur gélose au sang"],answer:1,diff:2,explication:"Gram- → Test oxydase. Oxydase+ : Pseudomonas, Neisseria, Campylobacter (non-fermentants ou micro-aérophiles). Oxydase- : Entérobactéries (Escherichia, Klebsiella, Salmonella, Shigella…). Puis galerie biochimique (API 20E).",tags:["Bactériologie","Test oxydase","Identification","Gram-"]},
  {id:"abm_bs8",prompt:"Pour orienter l'identification d'une bactérie Gram+, le test catalase différencie :",choices:["Gram+ des Gram-","Staphylocoques (catalase+) des Streptocoques (catalase-)","Bacilles des coques","Aérobies des anaérobies"],answer:1,diff:1,explication:"Gram+ coques → catalase. Catalase+ (dégagement O₂ dans H₂O₂) → Staphylococcus spp. Catalase- → Streptococcus, Enterococcus. Puis tests complémentaires : coagulase (S. aureus vs S. epidermidis), CAMP test (streptocoques).",tags:["Bactériologie","Test catalase","Staphylocoque","Streptocoque","Identification"]},
  {id:"abm_bs9",prompt:"Le milieu de Hajna-Kliger (KIA) est un milieu d'orientation permettant de détecter :",choices:["La sensibilité aux antibiotiques","La fermentation du glucose, du lactose, la production de gaz et d'H2S (pour les entérobactéries)","La sporulation","La sensibilité à la pénicilline"],answer:1,diff:2,explication:"KIA (Kligler-Iron-Agar) : culot (glucose) + pente (lactose). Lecture : pente/culot : K/K (alcalin/alcalin) = non fermentant ; K/A = glucose seul ; A/A = glucose + lactose. Gaz (bulles), H2S (noircissement).",tags:["Bactériologie","KIA","Hajna-Kliger","Milieux d'identification","Entérobactéries"]},
  {id:"abm_bs10",prompt:"La gélose Mueller-Hinton est le milieu standardisé utilisé pour :",choices:["La numération des entérobactéries","L'antibiogramme (sensibilité aux antibiotiques)","L'isolement des mycobactéries","La culture des levures"],answer:1,diff:1,explication:"Mueller-Hinton : milieu standardisé pour antibiogramme (méthode de diffusion Kirby-Bauer). Composition contrôlée pour reproductibilité. Incubation 37°C, 18-24h, atmosphère selon l'espèce. Lecture diamètres d'inhibition → EUCAST.",tags:["Bactériologie","Mueller-Hinton","Antibiogramme","Milieux"]},
  {id:"abm_bs11",prompt:"La gélose au sang frais permet de mettre en évidence le type d'hémolyse : l'hémolyse β (bêta) se caractérise par :",choices:["Un virage verdâtre autour des colonies","Une lyse totale des hématies avec zone transparente autour des colonies","L'absence de lyse","Une lyse partielle avec trouble"],answer:1,diff:2,explication:"Hémolyse β (complète) : lyse totale des hématies → zone transparente nette (Streptococcus pyogenes). Hémolyse α (incomplète) : virage verdâtre (dégradation partielle Hb → S. pneumoniae). Hémolyse γ : absence de lyse.",tags:["Bactériologie","Gélose au sang","Hémolyse","Streptocoque"]},
  {id:"abm_bs12",prompt:"Les colonies de type S (Smooth/lisse) en bactériologie présentent :",choices:["Une surface rugueuse et des bords irréguliers","Une surface lisse, des bords réguliers, un aspect bombé et une consistance crémeuse (suspension homogène)","Une forme filamenteuse","Un aspect muqueux filant"],answer:1,diff:1,explication:"Morphologie coloniale : S (Smooth) = lisse, bombé, régulier, crémeux → suspension homogène. M (Muqueuse) = lisse, bombé, filant (polysaccharides capsulaires). R (Rough) = rugueux, plat, bords dentelés → suspension hétérogène.",tags:["Bactériologie","Morphologie coloniale","Colonies","Identification macroscopique"]},
];

export const QB_ABM_CQ = [
  {id:"abm_cq1",prompt:"La carte de contrôle de Levey-Jennings représente :",choices:["L'évolution de la température de l'automate","Les valeurs du CQI en fonction du temps, avec des lignes-seuils à ±2DS et ±3DS autour de la moyenne cible","Le nombre de patients analysés par jour","Le taux de rejet des échantillons par l'automate"],answer:1,diff:1,explication:"La carte de Levey-Jennings est l'outil graphique du CQI. L'axe X représente les runs/jours successifs, l'axe Y la valeur mesurée. Les lignes ±1DS, ±2DS, ±3DS permettent d'appliquer les règles de Westgard.",tags:["Contrôle qualité","Levey-Jennings","CQI","Graphique"]},
  {id:"abm_cq2",prompt:"Le Z-score (score de standardisation) est calculé par la formule :",choices:["Z = (valeur obtenue × DS) / moyenne cible","Z = (valeur obtenue - moyenne cible) / DS","Z = DS / (valeur obtenue - moyenne cible)","Z = moyenne cible / (valeur obtenue + DS)"],answer:1,diff:1,explication:"Z = (valeur obtenue − moyenne cible) / DS. Il exprime l'écart en nombre d'écarts-types. Z = +2 signifie que la valeur est à +2DS au-dessus de la cible. Essentiel pour l'application automatisée des règles de Westgard.",tags:["Contrôle qualité","Z-score","Calcul","Westgard"]},
  {id:"abm_cq3",prompt:"La règle de Westgard 1:3s signifie :",choices:["Une valeur de CQ comprise entre ±1DS et ±2DS : alerte simple","Une valeur de CQ dépasse ±3DS : le run doit être rejeté (erreur aléatoire)","Trois valeurs consécutives du même côté de la moyenne","Un écart de 3DS entre deux niveaux de contrôle dans le même run"],answer:1,diff:1,explication:"1:3s = 1 valeur dépasse ±3DS. C'est une règle de rejet ferme évoquant une erreur aléatoire (contamination, dysfonctionnement soudain de l'appareil). Le run est invalidé et les résultats ne peuvent pas être rendus.",tags:["Contrôle qualité","Westgard","1:3s","Erreur aléatoire"]},
  {id:"abm_cq4",prompt:"La règle de Westgard 1:2s est qualifiée de règle :",choices:["De rejet ferme — le run est arrêté immédiatement","D'alerte — une valeur entre ±2DS et ±3DS déclenche une vigilance accrue mais ne rejette pas seule le run","D'erreur systématique — biais confirmé","De dérive — tendance sur plusieurs jours"],answer:1,diff:2,explication:"1:2s = 1 valeur entre 2DS et 3DS. C'est un signal d'alerte (warning) qui invite à renforcer la surveillance. Elle ne provoque pas le rejet du run à elle seule, mais doit inciter à vérifier les autres règles.",tags:["Contrôle qualité","Westgard","1:2s","Alerte"]},
  {id:"abm_cq5",prompt:"La règle 2:2s de Westgard détecte :",choices:["Deux valeurs consécutives dépassant ±3DS","Deux valeurs consécutives du même côté entre ±2DS et ±3DS → erreur systématique (biais)","Deux niveaux de CQ différents dépassant ±1DS","Deux runs consécutifs invalides"],answer:1,diff:2,explication:"2:2s = 2 valeurs consécutives du même côté, entre 2DS et 3DS. Cela évoque un biais (erreur systématique) : décalage de la calibration, dégradation d'un réactif, dérive de la température. Le run est rejeté.",tags:["Contrôle qualité","Westgard","2:2s","Erreur systématique","Biais"]},
  {id:"abm_cq6",prompt:"La règle R:4s de Westgard est déclenchée lorsque :",choices:["4 valeurs consécutives dépassent la même limite","La différence entre la valeur maximale et minimale d'un même run est ≥ 4DS (imprécision)","4 valeurs sont en dessous de la moyenne","La répétabilité est supérieure à 4%"],answer:1,diff:2,explication:"R:4s = Range : l'écart entre la valeur la plus haute et la plus basse dans un run dépasse 4DS. C'est un indicateur d'imprécision (erreur aléatoire large), souvent lié à une instabilité de l'appareil ou du réactif.",tags:["Contrôle qualité","Westgard","R:4s","Imprécision","Erreur aléatoire"]},
  {id:"abm_cq7",prompt:"La règle 4:1s de Westgard signale :",choices:["Une valeur dépassant 4 fois l'écart-type","Quatre valeurs consécutives du même côté de la moyenne à ±1DS → dérive progressive","Quatre runs successifs invalides","Quatre niveaux de contrôle différents hors limites"],answer:1,diff:2,explication:"4:1s = 4 valeurs consécutives toutes du même côté de la moyenne, chacune entre ±1DS et ±2DS. Indique une dérive progressive (erreur systématique en évolution) : vieillissement d'un réactif, dérive de l'étalonnage.",tags:["Contrôle qualité","Westgard","4:1s","Dérive","Erreur systématique"]},
  {id:"abm_cq8",prompt:"La règle 10:x de Westgard est satisfaite lorsque :",choices:["Dix valeurs consécutives dépassent ±2DS","Dix valeurs consécutives se trouvent toutes du même côté de la moyenne (tendance systématique)","Dix runs consécutifs sont rejetés","Dix patients ont des résultats aberrants"],answer:1,diff:2,explication:"10:x = 10 valeurs consécutives toutes du même côté de la moyenne (sans nécessairement dépasser ±1DS). Indique une tendance systématique (trend) profonde, souvent liée à une dérive lente de la calibration ou à la dégradation progressive d'un réactif.",tags:["Contrôle qualité","Westgard","10:x","Tendance systématique"]},
  {id:"abm_cq9",prompt:"Le CQI (Contrôle Qualité Interne) est :",choices:["Un programme inter-laboratoires évalué par un organisme extérieur","Un matériau de contrôle inclus dans chaque série analytique pour vérifier la reproductibilité de la méthode","Le résultat moyen des patients de la journée","Un test de calibration effectué une fois par semaine"],answer:1,diff:1,explication:"Le CQI consiste à analyser des matériaux de contrôle (sérums commerciaux, lyophilisats) à valeurs connues à chaque série analytique. Il vérifie la reproductibilité et la stabilité de la méthode en temps réel, avant validation des résultats patients.",tags:["Contrôle qualité","CQI","Contrôle interne","Qualité analytique"]},
  {id:"abm_cq10",prompt:"Le CQA (Contrôle Qualité Analytique externe) ou EEQ correspond à :",choices:["L'utilisation de deux niveaux de contrôle sur le même automate","Un programme inter-laboratoires (ex : CTCB, Labquality en France) permettant de comparer les résultats d'un laboratoire à ceux de ses pairs","La vérification des thermomètres et balances","Le contrôle de l'environnement de travail"],answer:1,diff:2,explication:"L'EEQ (Évaluation Externe de la Qualité) ou CQA est obligatoire pour l'accréditation ISO 15189. Des échantillons de valeurs inconnues sont envoyés à plusieurs laboratoires ; les résultats sont comparés à la moyenne des pairs. Ex : CTCB (biochimie), GBEA, Labquality.",tags:["Contrôle qualité","CQA","EEQ","Inter-laboratoire","ISO 15189"]},
  {id:"abm_cq11",prompt:"La métrique Sigma (Sigma metric) est calculée par :",choices:["Sigma = CV / (TEa + biais)","Sigma = (TEa − biais) / CV","Sigma = biais × CV / TEa","Sigma = TEa / (biais + DS)"],answer:1,diff:3,explication:"Sigma = (TEa − biais) / CV. TEa = erreur totale tolérée (définie par CLIA ou RiliBÄK). Le biais est l'erreur systématique et CV mesure l'imprécision. Un sigma ≥ 6 indique une performance analytique excellente (peu de contrôles nécessaires). Sigma < 3 = méthode à risque.",tags:["Contrôle qualité","Sigma","TEa","Biais","CV","Performance analytique"]},
  {id:"abm_cq12",prompt:"Pour un analyte avec une cible = 100 mg/dL et DS = 3 mg/dL, la règle 1:3s est déclenchée si la valeur de CQ est :",choices:["< 94 ou > 106 mg/dL","< 91 ou > 109 mg/dL","< 97 ou > 103 mg/dL","< 85 ou > 115 mg/dL"],answer:1,diff:2,explication:"1:3s = valeur au-delà de ±3DS. Limite inférieure = 100 − (3 × 3) = 91 mg/dL. Limite supérieure = 100 + (3 × 3) = 109 mg/dL. Toute valeur de CQ < 91 ou > 109 mg/dL déclenche le rejet immédiat du run selon la règle 1:3s.",tags:["Contrôle qualité","Westgard","1:3s","Application numérique","DS"]},
];

export const QB_ABM_CHROMATO = [
  {id:"abm_ch1",prompt:"Le facteur de rétention Rf en CCM (Chromatographie sur Couche Mince) est calculé par :",choices:["Rf = distance front solvant / distance tache","Rf = distance tache / distance front solvant","Rf = temps de rétention / temps mort","Rf = masse molaire / vitesse phase mobile"],answer:1,diff:1,explication:"Rf (Retardation factor) = distance parcourue par la tache / distance parcourue par le front du solvant. Sa valeur est comprise entre 0 et 1. Caractéristique d'un composé dans un système solvant/phase stationnaire donné.",tags:["Chromatographie","CCM","Rf","Phase stationnaire"]},
  {id:"abm_ch2",prompt:"En CCM, la révélation sous UV à 254 nm fonctionne car :",choices:["Elle détruit les composés aromatiques","Les molécules conjuguées absorbent à cette longueur d'onde et apparaissent en sombre sur fond fluorescent","Elle colore les acides aminés en rouge","Elle provoque une fluorescence bleue de la silice"],answer:1,diff:2,explication:"Les plaques de silice CCM contiennent un indicateur de fluorescence (F254) qui émet sous UV à 254 nm. Les composés absorbant à cette longueur d'onde (aromatiques, conjugués) éteignent la fluorescence → taches sombres sur fond vert. Autres révélateurs : ninhydrine (acides aminés), iode.",tags:["Chromatographie","CCM","Révélation","UV"]},
  {id:"abm_ch3",prompt:"En HPLC en phase inverse, la phase stationnaire est :",choices:["Polaire (silice non greffée)","Apolaire (silice greffée C18/octadécyl) et la phase mobile est polaire/aqueuse","Un gel poreux pour la séparation par taille","Une résine échangeuse de cations"],answer:1,diff:2,explication:"HPLC phase inverse (la plus utilisée en pratique) : phase stationnaire apolaire (C18 ou C8) + phase mobile polaire aqueuse (eau/acétonitrile ou méthanol). Les composés polaires éluent en premier. La phase normale (inverse) utilise silice polaire + solvant apolaire.",tags:["Chromatographie","HPLC","Phase inverse","C18"]},
  {id:"abm_ch4",prompt:"La pression de travail en HPLC est typiquement de :",choices:["1 à 5 bars (pression atmosphérique)","50 à 300 bars","500 à 1000 bars","< 1 bar"],answer:1,diff:1,explication:"L'HPLC (High Performance Liquid Chromatography) utilise une haute pression (50-300 bars) pour forcer la phase mobile à travers la phase stationnaire de granulométrie fine (3-5 µm). Cette pression permet des séparations rapides et efficaces impossible en chromatographie liquide classique.",tags:["Chromatographie","HPLC","Pression","Technique"]},
  {id:"abm_ch5",prompt:"En chromatographie d'exclusion de taille (SEC), quel type de molécule élue en premier ?",choices:["Les petites molécules (entrent dans tous les pores)","Les grandes molécules (exclues des pores, éluent sans retard)","Les molécules de taille moyenne","Les molécules les plus chargées"],answer:1,diff:2,explication:"SEC (Size Exclusion Chromatography) : phase stationnaire = gel poreux. Les grosses molécules ne peuvent pas entrer dans les pores → elles prennent le chemin le plus court et éluent EN PREMIER. Les petites molécules pénètrent dans les pores et éluent tardivement. Applications : protéines, polymères.",tags:["Chromatographie","SEC","Exclusion de taille","Protéines"]},
  {id:"abm_ch6",prompt:"En CPG (Chromatographie en Phase Gazeuse), le gaz vecteur est :",choices:["Le dioxyde de carbone (CO₂) sous haute pression","L'hélium ou l'azote (gaz inertes)","La vapeur d'eau","L'oxygène"],answer:1,diff:1,explication:"CPG (GC) : le gaz vecteur (phase mobile gazeuse) transporte l'analyte vaporisé à travers la colonne capillaire. L'hélium est préféré (meilleure efficacité, vitesse optimale Van Deemter) ; l'azote est utilisé si moins de coût requis. L'analyte doit être volatil ou rendu volatil par dérivation.",tags:["Chromatographie","CPG","Gaz vecteur","Phase gazeuse"]},
  {id:"abm_ch7",prompt:"Le détecteur FID (Flame Ionization Detector) utilisé en CPG détecte :",choices:["Uniquement les composés halogénés","Tous les composés organiques carbonés (ionisation dans une flamme H₂/air)","Uniquement les composés inorganiques","Les espèces radioactives"],answer:1,diff:2,explication:"FID : le plus universel pour composés organiques. La flamme H₂/air ionise les composés carbonés → courant électrique proportionnel à la quantité de carbone. Très sensible et linéaire. Non destructif pour ECD. Applications : solvants, alcools, arômes, pesticides, parfums.",tags:["Chromatographie","CPG","FID","Détecteur"]},
  {id:"abm_ch8",prompt:"La chromatographie d'affinité permet une purification très haute en une seule étape grâce à :",choices:["La différence de taille des protéines","L'interaction spécifique entre un ligand immobilisé et la molécule cible (ex : Protéine A pour IgG, nickel-NTA pour His-tag)","La différence de charge électrique","Le gradient de sel"],answer:1,diff:2,explication:"Chromatographie d'affinité : ligand spécifique immobilisé sur la phase stationnaire. Seule la molécule cible s'y lie. Exemples : Protéine A → IgG ; nickel-NTA → protéines His-tag ; glutathion → protéines GST. Élution par compétition (excès de ligand libre) ou changement de pH. Pureté > 95% en une étape.",tags:["Chromatographie","Affinité","Purification","Protéines"]},
  {id:"abm_ch9",prompt:"L'élution par gradient de sel (NaCl) en chromatographie d'échange d'ions permet :",choices:["De précipiter les protéines","De déplacer les protéines liées à la phase stationnaire chargée en augmentant progressivement la force ionique","De séparer les énantiomères","De dénommer les fractions selon leur masse molaire"],answer:1,diff:2,explication:"IEC (Ion Exchange Chromatography) : la phase stationnaire chargée retient les protéines de charge opposée. L'élution par gradient de sel (augmentation progressive NaCl) déplace les protéines : celles qui interagissent faiblement éluent d'abord, les plus fortement liées éluent tardivement. Alternative : gradient de pH.",tags:["Chromatographie","Échange d'ions","IEC","Gradient de sel"]},
  {id:"abm_ch10",prompt:"Le nombre de plateaux théoriques (N) est un paramètre d'efficacité d'une colonne chromatographique. Un grand N signifie :",choices:["Une mauvaise séparation (pics larges)","Une bonne efficacité (pics fins et bien résolus)","Une phase stationnaire très polaire","Un temps d'analyse long"],answer:1,diff:2,explication:"N (nombre de plateaux théoriques) = L / H (longueur colonne / hauteur d'un plateau théorique). Plus N est grand, plus les pics sont fins → meilleure résolution. La relation de Van Deemter (H vs vitesse phase mobile) permet d'optimiser la vitesse d'élution pour minimiser H et maximiser N.",tags:["Chromatographie","Efficacité","Plateaux théoriques","Van Deemter"]},
  {id:"abm_ch11",prompt:"La chromatographie chirale permet de séparer :",choices:["Des isomères de masse","Des énantiomères (images miroir non superposables) grâce à une colonne à phase stationnaire chirale","Des polymères selon leur taille","Des ions selon leur charge"],answer:1,diff:2,explication:"Les énantiomères (R et S, D et L) ont les mêmes propriétés physico-chimiques dans un environnement achiral mais des activités biologiques très différentes. La colonne chirale crée un environnement dissymétrique → les interactions diastéréoisomériques transitoires diffèrent → séparation possible. Essentiel en pharmacie (ex : ibuprofène, amino-acides).",tags:["Chromatographie","Chirale","Énantiomères","Pharmacie"]},
  {id:"abm_ch12",prompt:"En HPLC, le détecteur barrette de diodes (DAD) présente l'avantage de :",choices:["Mesurer la masse des analytes","Enregistrer l'absorption UV-Vis sur toute une gamme de longueurs d'onde simultanément, permettant un spectre complet pour chaque pic","Détecter uniquement les composés fluorescents","Mesurer la radioactivité des composés"],answer:1,diff:2,explication:"DAD (Diode Array Detector) : contrairement au détecteur UV à longueur d'onde fixe, le DAD enregistre l'absorbance sur toute la gamme UV-Vis (190-800 nm) à chaque instant. On obtient un chromatogramme 3D (temps, longueur d'onde, absorbance) permettant la confirmation de l'identité d'un pic par son spectre UV caractéristique.",tags:["Chromatographie","HPLC","DAD","Détecteur UV"]},
];

export const QB_ABM_HEMOSTASE = [
  {id:"abm_hm1",prompt:"Le bilan d'hémostase de 1ère intention comprend obligatoirement :",choices:["Uniquement l'INR","TP (Taux de Quick), TCA (Temps de Céphaline Activée) et numération plaquettaire","NFS seule","Fibrinogène seul"],answer:1,diff:1,explication:"Bilan standard hémostase : TP (voie extrinsèque : VII, X, V, II, I) + TCA (voie intrinsèque : XII, XI, IX, VIII, X, V, II, I) + plaquettes. Le fibrinogène est souvent ajouté en 2ème intention ou dans les bilans pré-opératoires, de grossesse, de thrombophilie ou de CIVD suspectée.",tags:["Hémostase","TP","TCA","Bilan"]},
  {id:"abm_hm2",prompt:"Le temps de Quick (TP) est allongé dans TOUTES les situations SAUF :",choices:["Insuffisance hépatocellulaire sévère","Traitement par AVK","Hémophilie A (déficit facteur VIII)","CIVD avec consommation des facteurs"],answer:2,diff:2,explication:"Le TP explore la voie extrinsèque (VII) et commune (X, V, II, I). L'hémophilie A = déficit facteur VIII (voie intrinsèque uniquement) → TP NORMAL, TCA allongé. Les AVK inhibent les facteurs vitamine K-dépendants (II, VII, IX, X) → TP allongé. L'insuffisance hépatocellulaire → ↓ synthèse de tous les facteurs → TP allongé.",tags:["TP","Hémostase","Voie extrinsèque","Hémophilie"]},
  {id:"abm_hm3",prompt:"L'INR cible pour un patient sous AVK pour fibrillation auriculaire est :",choices:["0.5-1.0 (sous-thérapeutique)","2.0-3.0","3.5-4.5","1.0-1.5"],answer:1,diff:1,explication:"INR cible 2-3 : fibrillation auriculaire (FA), thrombose veineuse profonde (TVP), embolie pulmonaire (EP), valvulopathie. INR cible 2.5-3.5 : prothèse valvulaire mécanique mitrale. INR > 5 = risque hémorragique majeur (antidote : vitamine K IV ± PPSB si urgence).",tags:["INR","AVK","Anticoagulation","FA"]},
  {id:"abm_hm4",prompt:"Le TCA est allongé ISOLÉMENT (TP normal) dans :",choices:["L'insuffisance hépatocellulaire","L'hémophilie A ou B (déficit VIII ou IX)","Le traitement par AVK","La CIVD débutante"],answer:1,diff:2,explication:"TCA isolément allongé (TP normal) : hémophilie A (FVIII↓), hémophilie B (FIX↓), maladie de von Willebrand sévère (↓ FVIII associé), déficit FXII, XI, traitement par héparine, syndrome des antiphospholipides (anticoagulant lupique). L'AVK allonge les DEUX (TP + TCA). L'insuffisance hépatocellulaire aussi.",tags:["TCA","Hémophilie","Voie intrinsèque","Diagnostic"]},
  {id:"abm_hm5",prompt:"La thrombophilie constitutionnelle la plus fréquente en Europe caucasienne est :",choices:["Déficit en protéine C","Mutation du facteur V Leiden (résistance à la protéine C activée)","Déficit en antithrombine","Mutation de la prothrombine G20210A"],answer:1,diff:2,explication:"Facteur V Leiden (mutation R506Q) : fréquence ≈ 5% des Caucasiens (hétérozygotes). Résistance à la protéine C activée → hypercoagulabilité. Risque TVP ×5-8 (hétérozygote). Déficit AT III / protéine C / protéine S = rares mais risque élevé. Mutation prothrombine G20210A = 2ème plus fréquente (2-3%).",tags:["Thrombophilie","Facteur V Leiden","Protéine C activée","TVP"]},
  {id:"abm_hm6",prompt:"Les D-dimères sont élevés dans toutes ces situations SAUF :",choices:["Embolie pulmonaire","Grossesse physiologique","Thrombose veineuse profonde","Hémophilie A non traitée (sans thrombose)"],answer:3,diff:2,explication:"D-dimères = marqueurs de dégradation de la fibrine réticulée (fibrinolyse). Élevés si : TVP, EP (excellente VPN < 500 µg/L pour exclure TVP/EP), grossesse (augmentation physiologique), post-opératoire, cancer, CIVD, sepsis, vieillesse. L'hémophilie A sans thrombose n'entraîne PAS d'élévation des D-dimères (saignement, pas de caillot).",tags:["D-dimères","TVP","EP","Spécificité"]},
  {id:"abm_hm7",prompt:"Dans un bilan de CIVD (Coagulation Intravasculaire Disséminée), le biologiste s'attend à :",choices:["TP normal, TCA normal, fibrinogène élevé, plaquettes normales","TP allongé, TCA allongé, fibrinogène effondré (< 1 g/L), D-dimères très élevés, thrombopénie"],answer:1,diff:2,explication:"CIVD = activation massive et incontrôlée de la coagulation → consommation de TOUS les facteurs et des plaquettes. Résultat biologique caractéristique : TP ↓, TCA ↑, fibrinogène < 1 g/L, D-dimères > 2 µg/mL (fibrinolyse réactionnelle), plaquettes < 100 G/L. Causes : sepsis sévère, leucémie aiguë, polytraumatisme, HELLP syndrome.",tags:["CIVD","Coagulation","Urgence biologique","Bilan"]},
  {id:"abm_hm8",prompt:"Le dosage des D-dimères est INUTILE chez un patient présentant :",choices:["Une douleur de mollet avec score de Wells bas","Un arrêt cardiaque récent admis en réanimation","Une fièvre isolée sans signe de TVP/EP","Un patient de 35 ans avec douleur thoracique et probabilité clinique faible"],answer:1,diff:3,explication:"En réanimation, les D-dimères sont quasi-universellement élevés (inflammation systémique, procédures, réanimation) → valeur diagnostique nulle dans ce contexte. Ils sont utiles pour EXCLURE TVP/EP chez les patients à faible probabilité clinique (score de Wells < 2). En cas de haute probabilité clinique, l'imagerie (écho-doppler, angio-TDM) est directement indiquée.",tags:["D-dimères","TVP","Probabilité clinique","Wells"]},
  {id:"abm_hm9",prompt:"La thrombopénie immune primaire (PTI) est diagnostiquée quand :",choices:["La numération plaquettaire est < 150 G/L quelle que soit la cause","Les plaquettes sont < 100 G/L et toutes les autres causes ont été éliminées (auto-immunité)","Le TP est allongé et les plaquettes basses","Le fibrinogène est effondré et les D-dimères élevés"],answer:1,diff:2,explication:"PTI (ex-purpura thrombopénique idiopathique) : thrombopénie autoimmune par auto-anticorps anti-plaquettes (anti-GPIIb/IIIa ou anti-GPIb). Diagnostic d'exclusion : écarter leucémie, lupus, médicaments, VIH, VHC, H. pylori... Traitement : corticoïdes ± IgIV en 1ère ligne. Romiplostim/eltrombopag si réfractaire.",tags:["PTI","Thrombopénie","Auto-immunité","Plaquettes"]},
  {id:"abm_hm10",prompt:"La maladie de von Willebrand (MvW) de type 1 est caractérisée par :",choices:["Un déficit sévère quantitatif en FvW (< 1%) et une hémophilie A associée","Une diminution modérée de la quantité de FvW, allongeant le TCA et augmentant le TS (temps de saignement)","Une anomalie qualitative du FvW avec des multimères anormaux (type 2)","Une absence totale du FvW (type 3)"],answer:1,diff:2,explication:"MvW type 1 (75%) : déficit QUANTITATIF partiel du facteur de von Willebrand (FvW 30-50% de la normale). TCA allongé (car FvW chaperone le FVIII). TS/PFA-100 allongé (FvW = adhésion plaquettaire via GPIb). FVIII légèrement diminué. Traitement : DDAVP (desmopressine) libère les stocks endothéliaux de FvW.",tags:["Maladie de von Willebrand","FvW","TCA","TS"]},
  {id:"abm_hm11",prompt:"L'antithrombine III (ATIII) est le principal inhibiteur naturel de :",choices:["La fibrinolyse (inhibe le plasminogène)","La thrombine (IIa) et du facteur Xa, avec un effet multiplié par 1000 en présence d'héparine"],answer:1,diff:2,explication:"L'ATIII (ou AT) inhibe la thrombine (IIa) et le facteur Xa (principalement) par formation de complexes covalents. En présence d'héparine (non fractionnée ou HBPM), l'activité de l'AT est augmentée × 1000. Déficit en ATIII (< 70%) = thrombophilie héréditaire à risque élevé. Dosage : activité et antigène (déficits fonctionnels ou quantitatifs).",tags:["Antithrombine III","Coagulation","Héparine","Thrombophilie"]},
  {id:"abm_hm12",prompt:"La surveillance biologique d'un patient sous HBPM (enoxaparine) pour une TVP se fait par :",choices:["INR (toutes les 48h)","Mesure de l'activité anti-Xa (niveau standard thérapeutique 0.5-1.0 UI/mL selon l'indication)","TCA (2 × temps témoin)","Fibrinogène toutes les 24h"],answer:1,diff:2,explication:"HBPM (héparines bas poids moléculaire) : surveillance biologique de ROUTINE non recommandée dans les cas standards (posologie fixe selon le poids). MAIS indication de mesure anti-Xa si : insuffisance rénale (DFGe < 30), obésité (IMC > 40), grossesse, cas hémorragiques ou thrombotiques. Cible anti-Xa selon l'HBPM et l'indication.",tags:["HBPM","Anti-Xa","Enoxaparine","Surveillance"]},
];

export const QB_ABM_IMMUNO_TRANSF = [
  {id:"abm_it1",prompt:"Le groupage sanguin ABO repose sur deux réactions complémentaires :",choices:["Test de Coombs direct + test de Coombs indirect","Beth-Vincent (épreuve globulaire avec anti-A et anti-B) + Simonin (épreuve sérique avec GR-tests A, B, O)","Test de Kleihauer + groupage Rhésus","RAI + groupage ABO"],answer:1,diff:1,explication:"Beth-Vincent : détection des Ag A et/ou B sur les GR du patient (avec anticorps anti-A et anti-B). Simonin : détection des Ac correspondants dans le sérum du patient (avec GR-tests A, B). Les deux résultats DOIVENT être concordants. Un groupage ABO nécessite 2 déterminations concordantes sur 2 prélèvements.",tags:["Groupage ABO","Beth-Vincent","Simonin","Transfusion"]},
  {id:"abm_it2",prompt:"Le système Rhésus comporte 5 antigènes principaux. L'antigène le plus immunogène est :",choices:["C","D (RH1) — présent chez 85% des Caucasiens (RH positif)","c","E"],answer:1,diff:1,explication:"Système RH : 5 Ag principaux : D (RH1), C (RH2), E (RH3), c (RH4), e (RH5). L'Ag D est de très loin le plus immunogène : une transfusion D+ chez un receveur D- → 80% de chance d'allo-immunisation anti-D. Deux déterminations concordantes par 2 réactifs monoclonaux distincts sont requises pour la détermination RH.",tags:["Rhésus","Antigène D","RH1","Immunogénicité"]},
  {id:"abm_it3",prompt:"La Recherche d'Anticorps Irréguliers (RAI) est valable pendant :",choices:["30 jours en toute circonstance","72 heures en contexte transfusionnel récent (< 3 mois depuis la dernière transfusion ou grossesse) ou 21 jours sinon","6 mois si aucune grossesse ni transfusion antérieure","Indéfiniment si la première RAI est négative"],answer:1,diff:2,explication:"RAI : délai de validité 72h en transfusion si historique immunisant récent (transfusion ou grossesse dans les 3 mois). En l'absence d'événement immunisant récent : valable 21 jours. Obligatoire avant toute transfusion de CGR. La RAI dépiste les Ac anti-GR (hors ABO) qui pourraient provoquer une réaction hémolytique retardée.",tags:["RAI","Anticorps irréguliers","Transfusion","Délai validité"]},
  {id:"abm_it4",prompt:"Un concentré de globules rouges (CGR) compatible pour une transfusion doit être :",choices:["Uniquement de même groupe ABO","ABO-RH compatible ET RAI négative pour les Ac pertinents ET épreuve de compatibilité au laboratoire (ECL) si indiqué","RH positif pour tous les patients","Uniquement de même groupe RH (Rhésus)"],answer:1,diff:2,explication:"Compatibilité transfusionnelle CGR : groupe ABO identique (ou compatible) + RH1(D) compatible + phénotypage RH-KEL (C, E, Kell) si patient à risque d'allo-immunisation (femme en âge de procréer, polytransfusé, drépanocytaire, aplasique) + RAI négative + ECL (épreuve de compatibilité au labo) si Ac détecté à la RAI.",tags:["Transfusion","CGR","Compatibilité","Phénotypage"]},
  {id:"abm_it5",prompt:"L'accident transfusionnel hémolytique IMMÉDIAT est le plus grave car :",choices:["Il survient toujours 5-7 jours après la transfusion","Il est causé par une incompatibilité ABO → hémolyse intravasculaire massive (activation complément) → choc, CIVD, IRA"],answer:1,diff:2,explication:"Incompatibilité ABO = erreur de groupe → Ac naturels (IgM) anti-A ou anti-B du receveur activent le complément → hémolyse intravasculaire massive, CIVD, IRA. Souvent causé par une erreur d'identité (FAQSS = Faute Attribuée à la Qualité des Soins de Sécurité). Mortalité élevée. L'hémolyse retardée (anti-Rh) survient J5-J14 : moins grave.",tags:["Accident transfusionnel","ABO","Hémolyse","Sécurité transfusionnelle"]},
  {id:"abm_it6",prompt:"Le test de Coombs INDIRECT (TCI / test indirect à l'antiglobuline = IAT) permet de :",choices:["Détecter les Ac fixés sur les GR du patient (diagnostic AHAI)","Rechercher les Ac anti-GR libres dans le sérum du patient (RAI, compatibilité pré-transfusionnelle)","Mesurer les D-dimères","Identifier le phénotype HLA"],answer:1,diff:2,explication:"TCI (IAT) : sérum patient + GR-tests → incubation → centrifugation → ajout antiglobuline humaine. Si les Ac du sérum se sont fixés sur les GR-tests → agglutination = positif. Applications : RAI (recherche d'allo-Ac), épreuve de compatibilité, dépistage Ac IgG (vs TCD qui détecte les Ac déjà fixés sur les GR DU patient).",tags:["Coombs indirect","IAT","RAI","Sérologie transfusionnelle"]},
  {id:"abm_it7",prompt:"Les plaquettes d'aphérèse (CPA) par opposition aux mélanges de concentrés plaquettaires (MCP) ont comme avantage :",choices:["Elles sont moins coûteuses","Elles exposent le receveur à un seul donneur (moindre risque d'allo-immunisation HLA et d'infection)"],answer:1,diff:2,explication:"CPA (concentré de plaquettes d'aphérèse) = 1 seul donneur → exposition limitée à 1 donneur → moindre risque d'allo-immunisation HLA (important chez les patients polytransfusés ou greffés) et de contamination virale. MCP = mélange de 4-6 donneurs. Le délai de conservation des plaquettes est de 5 jours (fragilité + risque bactérien).",tags:["Plaquettes","CPA","Aphérèse","Allo-immunisation HLA"]},
  {id:"abm_it8",prompt:"La transfusion isogroupe signifie que le CGR transfusé est :",choices:["Uniquement de même groupe RH que le receveur","Du même groupe ABO ET du même phénotype RH1 (D) que le receveur","De groupe O négatif (universel)","ABO et RH différents du receveur"],answer:1,diff:1,explication:"Isogroupe = identique en ABO et en RH1(D). C'est la règle générale en transfusion. Le groupe O RH négatif est dit 'universel' (peut être donné à tous) mais reste réservé aux urgences vitales (stock limité). Le phénotypage étendu RH-KEL est indiqué chez certains receveurs (femmes en âge de procréer, drépanocytaires).",tags:["Transfusion","Isogroupe","ABO","RH1"]},
  {id:"abm_it9",prompt:"En immunologie, le principe de l'ELISA en sandwich pour doser un Ag est :",choices:["Anticorps marqué direct sur l'Ag sans phase solide","Ac de capture sur plaque → Ag de l'échantillon → Ac de détection conjugué enzyme → substrat → signal colorimétrique proportionnel à l'Ag"],answer:1,diff:1,explication:"ELISA sandwich : (1) Ac de capture (fixé sur plaque 96 puits), (2) ajout de l'échantillon (Ag se lie), (3) Ac de détection (conjugué enzyme : HRP ou alkaline phosphatase), (4) substrat chromogène (TMB → bleu → jaune après arrêt). Absorbance = proportionnelle à [Ag]. Courbe d'étalonnage = quantification. Technique de référence en immunodosage.",tags:["ELISA","Sandwich","Immunodosage","Technique"]},
  {id:"abm_it10",prompt:"La technique d'agglutination sur colonne (gel-test, DiaMed) est avantageuse en immunohématologie car :",choices:["Elle permet le dosage quantitatif des Ac","Elle standardise la lecture, améliore la reproductibilité et archive les résultats (microcolonnes de gel avec billes de Sephadex)"],answer:1,diff:2,explication:"Gel-test (DiaMed/Bio-Rad) : GR + sérum ajoutés dans la microcolonne de gel de Sephadex → centrifugation → GR agglutinés restent en surface (positif) ; GR libres traversent le gel (négatif). Avantages : lecture standardisée (facile à archiver, photographier), reproductibilité, sensibilité élevée, réduction des erreurs de manipulation vs la méthode en tube.",tags:["Gel-test","Immunohématologie","DiaMed","Groupage"]},
  {id:"abm_it11",prompt:"La numération des lymphocytes CD4 chez un patient VIH permet de :",choices:["Mesurer la charge virale du VIH","Évaluer l'état d'immunodépression et décider du traitement préventif anti-infectieux (< 200/µL → prophylaxie Pneumocystis)"],answer:1,diff:1,explication:"Lymphocytes CD4+ (T helper) = cellules cibles du VIH. Taux normal > 500/µL. < 350/µL → instaurer ARV. < 200/µL → risque SIDA (Pneumocystis jirovecii, toxoplasmose cérébrale, CMV) → prophylaxie primaire. Technique : cytométrie en flux (CD4-CD3-CD45). Suivi tous les 3-6 mois.",tags:["VIH","CD4","Cytométrie en flux","Immunodépression"]},
  {id:"abm_it12",prompt:"Le dépistage néonatal en France par buvard Guthrie permet de détecter :",choices:["Uniquement la phénylcétonurie et l'hypothyroïdie","6 maladies : phénylcétonurie, hypothyroïdie, hyperplasie congénitale des surrénales, drépanocytose, mucoviscidose, MCAD"],answer:1,diff:2,explication:"Programme national de dépistage néonatal (PNDNN) : prélèvement sur buvard à J3. 6 pathologies : (1) Phénylcétonurie (PCU) : déficit PAH → phénylalanine ↑. (2) Hypothyroïdie congénitale : TSH ↑. (3) HCS : 17-OH-progestérone ↑. (4) Drépanocytose : Hb électrophorèse. (5) Mucoviscidose : trypsine immunoréactive (TIR). (6) MCAD : acylcarnitines.",tags:["Dépistage néonatal","Buvard Guthrie","Phénylcétonurie","Mucoviscidose"]},
];

export const QB_ABM_BIOL_MOL2 = [
  {id:"abm_bm1",prompt:"La PCR multiplex (ex : FilmArray, Luminex NxTAG) présente comme avantage principal :",choices:["Elle est moins chère qu'une PCR simple","Elle permet la détection simultanée de 10 à 30 agents pathogènes sur un seul prélèvement en 1 à 4 heures"],answer:1,diff:1,explication:"PCR multiplex (panel fermé) : plusieurs paires d'amorces dans le même réacteur → amplifications simultanées de plusieurs cibles. Ex : panel respiratoire (Grippe A/B, RSV, SARS-CoV-2, Rhinovirus, Legionella, Mycoplasma…) → 30 cibles en 1h. Révolution du diagnostic infectieux : délai de résultat, sensibilité, spécificité.",tags:["PCR multiplex","Panel infectieux","Diagnostic moléculaire","FilmArray"]},
  {id:"abm_bm2",prompt:"En PCR quantitative en temps réel (qPCR), le Ct (Cycle threshold) :",choices:["Est la concentration finale en produit amplifié","Est le cycle auquel la fluorescence dépasse le seuil détectable — plus il est bas, plus la concentration initiale de la cible est élevée"],answer:1,diff:1,explication:"Ct (ou Cq) = cycle seuil. Relation : chaque diminution de 3.3 cycles = multiplication par 10 de la quantité initiale de cibles (rendement PCR = 100%). Un Ct = 20 = 100× plus de cibles que Ct = 27. La courbe standard (dilutions connues de l'étalon) permet de calculer la concentration initiale → charge virale VIH, VHC, CMV, EBV.",tags:["qPCR","Cycle threshold","Ct","Quantification"]},
  {id:"abm_bm3",prompt:"La RT-PCR (Reverse Transcription PCR) est utilisée pour :",choices:["Amplifier directement l'ARN sans conversion","Convertir l'ARN en ADN complémentaire (ADNc) par une rétrotranscriptase AVANT l'amplification par PCR"],answer:1,diff:1,explication:"RT-PCR : l'ARN est un substrat instable ne pouvant pas être directement amplifié par PCR. La rétrotranscriptase (transcriptase inverse) copie l'ARN en ADNc stable → puis PCR conventionnelle ou qPCR sur l'ADNc. Applications : charges virales VIH (ARN viral), VHC, SARS-CoV-2 (ARN), expression génique (gènes d'intérêt dans les tumeurs).",tags:["RT-PCR","Rétrotranscriptase","ADNc","Charge virale"]},
  {id:"abm_bm4",prompt:"Le test HER2 sur tumeur mammaire peut être réalisé par immunohistochimie (IHC) et/ou par FISH. Le résultat IHC 2+ nécessite :",choices:["Un traitement par trastuzumab (Herceptin) immédiatement","Une confirmation par FISH (ou ISH) pour vérifier l'amplification du gène HER2"],answer:1,diff:2,explication:"HER2 : score IHC 0 ou 1+ = négatif (pas de traitement anti-HER2) ; 3+ = positif (traitement trastuzumab) ; 2+ = ÉQUIVOQUE → FISH/ISH obligatoire pour mesurer le nombre de copies du gène HER2 (rapport HER2/CEP17 ≥ 2 ou > 6 copies = amplifié = positif). Le trastuzumab (Herceptin) n'est actif que si HER2 amplifié/surexprimé.",tags:["HER2","Cancer du sein","IHC","FISH"]},
  {id:"abm_bm5",prompt:"La recherche de mutations BRCA1/2 dans les cellules tumorales (somatique) permet :",choices:["Uniquement d'évaluer le risque familial héréditaire","De prédire la réponse aux inhibiteurs PARP (olaparib, niraparib) et aux sels de platine dans les tumeurs ovariennes et mammaires"],answer:1,diff:2,explication:"Les mutations somatiques BRCA1/2 (acquises dans la tumeur, non héréditaires) altèrent la réparation par recombinaison homologue (HRD). Les inhibiteurs PARP exploitent la létalité synthétique : cellules avec BRCA muté + inhibition de PARP → incapacité à réparer l'ADN → mort cellulaire sélective. Indications : cancer de l'ovaire, du sein, de la prostate et du pancréas avec mutation BRCA.",tags:["BRCA","Inhibiteurs PARP","Oncologie","Létalité synthétique"]},
  {id:"abm_bm6",prompt:"L'instabilité des microsatellites (MSI) d'une tumeur colorectale est détectée par :",choices:["Séquençage NGS uniquement","PCR (comparaison des profils de répétitions microsatellites tumeur/tissu sain) ET/OU immunohistochimie des protéines MMR (perte d'expression MLH1, MSH2, MSH6, PMS2)"],answer:1,diff:2,explication:"Microsatellites = séquences répétées courtes (ex: CA, CAG). Instabilité si longueur différente dans la tumeur vs le tissu normal → dysfonction MMR. Détection : PCR (5 marqueurs Bethesda) avec fluorescence → comparaison des profils électrophorétiques. IHC : perte d'expression des protéines MMR = MSI-H. MSI-H = candidat aux anti-PD1 (pembrolizumab).",tags:["MSI","Microsatellites","MMR","IHC"]},
  {id:"abm_bm7",prompt:"La pharmacogénomique du gène DPYD concerne la toxicité du :",choices:["Paclitaxel","5-fluorouracile (5-FU) et de la capécitabine — les mutations DPYD réduisent le catabolisme → accumulation toxique"],answer:1,diff:2,explication:"DPYD (dihydropyrimidine déshydrogénase) : enzyme principale de dégradation du 5-FU. Mutations DPYD (ex : c.1905+1G>A, c.1679T>G, haplotype DPYD*2A) → activité réduite → accumulation de 5-FU → toxicités sévères (mucites, neutropénies grade 4, décès). Génotypage DPYD recommandé avant traitement 5-FU (circulaire ANSM 2019). Dose ajustée selon l'activité résiduelle.",tags:["DPYD","5-fluorouracile","Pharmacogénomique","Toxicité"]},
  {id:"abm_bm8",prompt:"Le séquençage Sanger est choisi pour des mutations spécifiques plutôt que le NGS car :",choices:["Il séquence le génome entier en moins de temps","Il offre une haute précision sur une région courte ciblée (< 1000 pb), résultat rapide, moins coûteux pour une cible unique"],answer:1,diff:2,explication:"Sanger (ddNTPs, électrophorèse capillaire) : séquence 200-1000 pb, résultat en quelques heures, précision ≥ 99.9%, coût bas pour 1-2 amplicons. Mais limité à une région à la fois. NGS préféré pour panels multi-gènes (oncologie, maladies rares, pharmacogénomique). Sanger reste gold standard pour confirmation de variants détectés par NGS.",tags:["Séquençage Sanger","NGS","Biologie moléculaire","Oncologie"]},
  {id:"abm_bm9",prompt:"L'ADN tumoral circulant (ctDNA / biopsie liquide) permet de :",choices:["Remplacer définitivement la biopsie tissulaire pour tous les diagnostics","Détecter les mutations tumorales dans un échantillon de sang (non invasif), utile pour le suivi de la maladie résiduelle minimale et la résistance aux traitements"],answer:1,diff:2,explication:"ctDNA (circulating tumor DNA) : fragments d'ADN d'origine tumorale libérés dans la circulation. Détectés par PCR digitale (ddPCR) ou NGS ultra-sensible. Applications : maladie résiduelle minimale (MRM) en leucémie, détection précoce de résistance (ex : mutation EGFR T790M sous gefitinib), monitoring de la réponse. Avantage : non invasif, répétable. Limite : sensibilité selon la charge tumorale.",tags:["ctDNA","Biopsie liquide","Maladie résiduelle","ddPCR"]},
  {id:"abm_bm10",prompt:"La FISH (hybridation in situ fluorescente) est utilisée en microbiologie clinique pour :",choices:["Amplifier des gènes de résistance","Identifier directement les micro-organismes dans des prélèvements (ex : identification rapide de levures sur prélèvement direct par sondes fluorescentes)"],answer:1,diff:3,explication:"PNA-FISH (Peptide Nucleic Acid-FISH) : sondes PNA fluorescentes spécifiques d'espèce pour Candida albicans (vert), C. parapsilosis (rouge)... Identification directe sur flacons d'hémocultures positifs → 3h vs 24-72h en culture. Applicable aussi à Staphylococcus aureus vs SCN. Coût élevé mais impact clinique majeur en sepsis.",tags:["FISH","Microbiologie","Candida","Hémocultures"]},
  {id:"abm_bm11",prompt:"Le métagénomique shotgun (mNGS) dans les prélèvements infectieux permet de :",choices:["Uniquement identifier les bactéries connues","Identifier tout micro-organisme (bactéries, virus, champignons, parasites) dans un prélèvement par séquençage de tous les acides nucléiques présents"],answer:1,diff:3,explication:"mNGS (métagénomique en shotgun / séquençage non ciblé) : extraction ADN/ARN total → séquençage → bioinformatique → comparaison à des bases de données. Identifie des agents pathogènes CONNUS et INCONNUS. Applications : infections non étiquetées après culture négative, encéphalites virales rares (La Crosse, VHSV), nouvelles entités. Délai encore long (48-72h) et coût élevé.",tags:["Métagénomique","mNGS","Pathogènes émergents","Diagnostic infectieux"]},
  {id:"abm_bm12",prompt:"En génomique constitutionnelle (maladies rares), l'analyse chromosomique par puce à ADN (CMA / array-CGH) permet de détecter :",choices:["Les mutations ponctuelles (SNPs) dans les gènes","Les variations du nombre de copies (CNV) sur tout le génome, avec une résolution bien supérieure au caryotype standard"],answer:1,diff:2,explication:"Array-CGH (Comparative Genomic Hybridization) / CMA (Chromosomal Microarray Analysis) : ADN patient et ADN référence hybridés sur une puce → fluorescence comparative. Détecte les CNV (délétions/duplications) > 50-200 kb (vs caryotype : > 10 Mb). Remplace en partie le caryotype dans le bilan étiologique des anomalies du développement (DI, malformations) et des fausses couches à répétition.",tags:["Array-CGH","CMA","CNV","Maladies rares"]},
];

