// QB_ABM_HEMATO_CELL
export const QB_ABM_HEMATO_CELL = [
  {id:"abm_hc1",prompt:"Le marqueur CD34 identifie :",choices:["Les lymphocytes T matures","Les cellules souches et progéniteurs hématopoïétiques — non exprimé sur les cellules matures","Les érythroblastes orthochromatiques","Les PNN matures"],answer:1,diff:1,explication:"CD34 est le marqueur de surface des cellules souches hématopoïétiques (CSH) et progéniteurs précoces. Son expression diminue au fil de la différenciation. En scRNA-seq, les clusters CD34+ sur un UMAP correspondent aux populations les plus immatures de la moelle osseuse.",tags:["Hématopoïèse","CD34","Cellule souche","Cell Atlas"]},
  {id:"abm_hc2",prompt:"BloodSpot (bloodspot.eu) permet de :",choices:["Doser le taux d'hémoglobine en ligne","Explorer l'expression génique de chaque type cellulaire hématopoïétique, des progéniteurs CD34+ aux cellules matures","Analyser un frottis sanguin par IA","Générer des ordonnances biologiques"],answer:1,diff:1,explication:"BloodSpot est un atlas transcriptomique de l'hématopoïèse. On y entre le nom d'un gène et on visualise son profil d'expression dans toutes les populations cellulaires sanguines. Outil pédagogique direct pour comprendre les marqueurs cellulaires.",tags:["Cell Atlas","BloodSpot","Hématopoïèse","scRNA-seq"]},
  {id:"abm_hc3",prompt:"Le gène HBB (bêta-globine) est spécifiquement exprimé dans :",choices:["Les lymphocytes T","Les érythrocytes et précurseurs érythroïdes","Les PNN et éosinophiles","Les plaquettes"],answer:1,diff:1,explication:"HBB code la chaîne bêta de l'hémoglobine. Expression restreinte à la lignée érythropoïétique. Sur BloodSpot, expression maximale dans les érythrocytes et précurseurs tardifs. Mutations : drépanocytose (Val6Glu) et thalassémie bêta.",tags:["Hématopoïèse","HBB","Érythrocytes","Génomique"]},
  {id:"abm_hc4",prompt:"Le gène MPO (myéloperoxydase) est un marqueur de :",choices:["La lignée lymphoïde B","La lignée granulo-monocytaire (myéloïde)","Les mégacaryocytes uniquement","Les cellules NK"],answer:1,diff:1,explication:"MPO est exprimé dans les granules azurophiles des PNN et monocytes. En immunophénotypage, MPO+ oriente vers une LAM. Sur BloodSpot et CELLxGENE, MPO est fortement exprimé dans les GMP et PNN matures.",tags:["Hématopoïèse","MPO","Lignée myéloïde","LAM"]},
  {id:"abm_hc5",prompt:"Sur un UMAP de scRNA-seq de moelle osseuse, chaque point représente :",choices:["Un gène","Une cellule individuelle, placée selon sa ressemblance transcriptomique globale","Un patient","Un tissu"],answer:1,diff:1,explication:"scRNA-seq : chaque cellule est séquencée individuellement. Le UMAP réduit la dimension (20 000+ gènes) en 2D : cellules proches = profils transcriptomiques similaires. Les clusters correspondent aux types cellulaires.",tags:["scRNA-seq","UMAP","Cell Atlas","Transcriptomique"]},
  {id:"abm_hc6",prompt:"La différenciation d'un CMP (progéniteur myéloïde commun) peut donner :",choices:["Des lymphocytes T et B uniquement","Des granulocytes, des monocytes ET des mégacaryocytes/érythrocytes","Des cellules NK uniquement","Des plasmocytes"],answer:1,diff:2,explication:"Hématopoïèse myéloïde : CSH → MPP → CMP → GMP (granulocytes + monocytes) ou MEP (mégacaryocytes + érythrocytes). Le CLP donne lymphocytes T, B et NK. Les points de branchement sont visibles sur les trajectoires de différenciation en scRNA-seq.",tags:["Hématopoïèse","CMP","Différenciation","Lignées"]},
  {id:"abm_hc7",prompt:"L'analyse de pseudotemps en scRNA-seq permet de :",choices:["Mesurer le temps de séquence des reads","Reconstruire la trajectoire de différenciation en ordonnant les cellules de la plus immature à la plus mature","Comparer des patients entre eux","Doser un ARNm dans le sang"],answer:1,diff:2,explication:"Pseudotemps (Monocle, RNA Velocity) : classe les cellules le long d'une trajectoire sans observations temporelles. Les CSH CD34+ sont au début, les PNN matures à la fin. Permet de visualiser l'activation progressive des gènes.",tags:["scRNA-seq","Pseudotemps","Différenciation","Cell Atlas"]},
  {id:"abm_hc8",prompt:"Sur CELLxGENE, le gène ITGA2B (CD41/GP-IIb) s'observe principalement dans :",choices:["Les lymphocytes B","Les mégacaryocytes et plaquettes (lignée thrombocytaire)","Les éosinophiles","Les cellules souches CD34+"],answer:1,diff:2,explication:"ITGA2B (GP-IIb, CD41) marque la lignée mégacaryocytaire-plaquettaire. Code la sous-unité alpha de l'intégrine aIIbb3 (récepteur du fibrinogène). Sur CELLxGENE, expression restreinte aux mégacaryocytes et leurs progéniteurs MEP tardifs.",tags:["Thrombopoïèse","ITGA2B","Mégacaryocytes","CELLxGENE"]},
  {id:"abm_hc9",prompt:"Une CSH est dite CD34+ CD38- car :",choices:["Elle exprime CD34 et CD38 simultanément","CD34 identifie les progéniteurs ; l'absence de CD38 signifie un stade très précoce, avant engagement dans une lignée","CD38 n'existe pas dans le sang","CD34- signifie qu'elle est lymphoïde"],answer:1,diff:2,explication:"CD34+CD38- = fenêtre immunophénotypique des CSH long terme. CD34+CD38+ = progéniteurs plus engagés. Au fil de la différenciation, CD34 diminue. Sur BloodSpot, CD38 est absent des clusters HSC et élevé dans les populations différenciées.",tags:["Cellule souche","CD34","CD38","Immunophénotypage"]},
  {id:"abm_hc10",prompt:"L'intérêt pédagogique de Cell Atlas pour les étudiants ABM est :",choices:["Remplacer le diagnostic biologique","Visualiser les profils transcriptomiques qui expliquent les marqueurs cliniques vus en hématologie","Automatiser les frottis sanguins","Prédire la médication des patients"],answer:1,diff:1,explication:"Cell Atlas comble le fossé entre les marqueurs cliniques (CD par cytométrie) et leur base moléculaire (expression génique). Comprendre pourquoi un PNN est MPO+ ou pourquoi un lymphocyte B est CD19+ devient concret en voyant l'expression de ces gènes sur un atlas.",tags:["Cell Atlas","Pédagogie","Hématologie","ABM"]},
];

// QB_ABM_IMMUNOPHENO_CELL
export const QB_ABM_IMMUNOPHENO_CELL = [
  {id:"abm_ip1",prompt:"La cytométrie en flux permet de :",choices:["Séquencer l'ADN de chaque cellule","Identifier et quantifier les types cellulaires par leurs marqueurs de surface (CD) via des anticorps fluorescents","Mesurer l'hémoglobine en g/dL","Réaliser une culture bactérienne"],answer:1,diff:1,explication:"La cytométrie en flux analyse les propriétés optiques des cellules individuelles. Des Ac couplés à des fluorochromes se lient aux marqueurs CD. Résultat : pourcentage et nombre absolu de chaque population (lymphocytes T, B, NK, blastes).",tags:["Immunophénotypage","Cytométrie","CD markers"]},
  {id:"abm_ip2",prompt:"Le marqueur CD3 identifie spécifiquement :",choices:["Les lymphocytes B","Les lymphocytes T (complexe CD3/TCR à leur surface)","Les cellules NK","Les PNN"],answer:1,diff:1,explication:"CD3 est le complexe signal associé au TCR. Présent sur tous les lymphocytes T matures (T CD4+, T CD8+, T gamma-delta). CD3+ = lymphocyte T. Sur CELLxGENE, le gène CD3E est exprimé exclusivement dans les clusters T cells.",tags:["Immunophénotypage","CD3","Lymphocytes T","TCR"]},
  {id:"abm_ip3",prompt:"CD19 et CD20 sont des marqueurs de :",choices:["Lymphocytes T","Lymphocytes B (du stade pro-B aux plasmablastes)","Cellules NK","Macrophages"],answer:1,diff:1,explication:"CD19 : exprimé dès le stade pro-B jusqu'aux plasmablastes (absent sur les plasmocytes matures). CD20 : absent des plasmocytes matures et des CSH. Cible du rituximab. Sur BloodSpot, MS4A1 (CD20) et CD19 montrent une expression restreinte à la lignée B.",tags:["Immunophénotypage","CD19","CD20","Lymphocytes B"]},
  {id:"abm_ip4",prompt:"CD14 est un marqueur caractéristique de :",choices:["Les lymphocytes T","Les monocytes et macrophages (co-récepteur du LPS)","Les érythrocytes","Les plaquettes"],answer:1,diff:1,explication:"CD14 est le co-récepteur du LPS bactérien (avec TLR4). Marque les monocytes circulants et les macrophages. Sur CELLxGENE dans le tissu 'sang', CD14 est exprimé quasi exclusivement dans les clusters monocytes classiques et non classiques.",tags:["Immunophénotypage","CD14","Monocytes","Macrophages"]},
  {id:"abm_ip5",prompt:"Dans une LAM, l'immunophénotypage montre typiquement :",choices:["CD3+ CD19+ (marqueurs lymphoïdes)","CD13+ CD33+ MPO+ CD117+ avec CD34 variable (marqueurs myéloïdes)","CD56+ CD16+ (marqueurs NK)","CD5+ CD23+ (marqueurs LLC)"],answer:1,diff:2,explication:"LAM : prolifération clonale de blastes myéloïdes. Immunophénotypage typique : CD13+, CD33+, CD117+ (c-Kit), MPO+ cytoplasmique. CD34 variable selon la sous-classification OMS.",tags:["LAM","Immunophénotypage","CD13","CD33","Blastes"]},
  {id:"abm_ip6",prompt:"Score de Matutes ≥4/5 dans la LLC (CD5+ CD23+ FMC7- Ig-faible CD22-faible) indique :",choices:["Une LAL T","Une LLC (leucémie lymphoïde chronique B confirmée)","Des lymphocytes NK","Un lymphome du manteau"],answer:1,diff:2,explication:"LLC = co-expression inhabituelle CD5 (normalement T) + CD19/CD23 (B) sur de petits lymphocytes B matures. Score de Matutes ≥4/5 = LLC confirmée. Score 3 = zone frontière avec lymphome du manteau (cycline D1 à exclure).",tags:["LLC","Score Matutes","Immunophénotypage","Lymphocytes B"]},
  {id:"abm_ip7",prompt:"La différence fondamentale entre cytométrie et scRNA-seq est :",choices:["Ils sont identiques","Cytométrie : ~50 marqueurs protéiques, rapide, clinique. scRNA-seq : 20 000+ gènes par cellule, découvre des sous-populations inédites","scRNA-seq est moins précis","Cytométrie séquence l'ADN"],answer:1,diff:2,explication:"Cytométrie : identification rapide, quantitative mais limitée aux protéines ciblées (panel prédéfini). scRNA-seq : vision non biaisée du transcriptome complet, découvre de nouvelles sous-populations, mais plus lent et coûteux. En clinique : cytométrie. En recherche : scRNA-seq.",tags:["Cytométrie","scRNA-seq","Immunophénotypage","Comparaison"]},
  {id:"abm_ip8",prompt:"Un fort CD34 sur les blastes d'une LAM signifie :",choices:["La LAM est guérie","Les blastes sont bloqués à un stade immature — ils expriment des marqueurs de progéniteurs au lieu de se différencier","CD34 est un marqueur de maturité","La LAM est forcément CD33-"],answer:1,diff:2,explication:"Dans les LAM, les cellules sont bloquées dans leur différenciation. Un fort CD34 sur les blastes indique un blocage à un stade très précoce (progéniteurs). La classification OMS tient compte de ce profil immunophénotypique.",tags:["LAM","CD34","Blastes","Différenciation"]},
  {id:"abm_ip9",prompt:"CD56 est le marqueur principal de :",choices:["Les plaquettes","Les lymphocytes T","Les cellules NK et plasmocytes pathologiques (myélome)","Les PNN"],answer:1,diff:2,explication:"CD56 (NCAM1) marque les cellules NK. Il est aussi exprimé dans le myélome multiple (plasmocytes CD38++ CD138+ CD56+). Les lymphocytes NKT sont CD3+ CD56+. Sur CELLxGENE, NCAM1 s'exprime dans les clusters NK cells.",tags:["CD56","Cellules NK","Myélome","Immunophénotypage"]},
  {id:"abm_ip10",prompt:"Le seuil de blastes ≥ 20% dans la moelle osseuse définit :",choices:["Un syndrome myélodysplasique","Une leucémie aiguë (LAM ou LAL selon le phénotype)","Une polyglobulie de Vaquez","Un myélome multiple"],answer:1,diff:2,explication:"OMS : leucémie aiguë = ≥20% de blastes dans la moelle (certaines translocations comme t(8;21) ou inv(16) suffisent quel que soit le % de blastes). Le phénotype (MPO+ = LAM ; TdT+, CD3+ ou CD19+ = LAL) est déterminé par immunophénotypage.",tags:["Blastes","Leucémie aiguë","OMS","Immunophénotypage"]},
];

