export const FICHES_ABM = [
  {id:"abm_f1",title:"Phase pré-analytique : tubes et prélèvements",bloc:"Bloc 2",tags:["Pré-analytique","Tubes","Qualité"],duree:15,niveau:"Fondations",qbank:"abm_preana",
    contenu:"**La phase pré-analytique = 40-70% des erreurs en biologie médicale**\n\n**Tubes de prélèvement (principaux) :**\n• Violet (EDTA) : NFS, réticulocytes, groupage, HbA1c\n• Bleu (citrate 3.2%) : hémostase (TP, TCA, fibrinogène) → REMPLISSAGE AU TRAIT obligatoire\n• Rouge/Gel : biochimie (glycémie, ionogramme, enzymes, sérologies) → attendre coagulation\n• Vert (héparine) : gaz du sang, certaines analyses urgentes\n• Gris (fluorure) : glycémie (inhibe glycolyse)\n\n**Ordre de remplissage :** Hémocultures → citrate → sec/gel → héparine → EDTA → fluorure\n\n**Interférences pré-analytiques :**\n• Hémolyse : ↑ faux K⁺, LDH, ASAT\n• Lipémie : fausse les dosages spectrophotométriques\n• Ictère : interfère aux λ ≈ 460 nm\n• Garrot > 1 min : hémoconcentration, pseudohyperkaliémie\n\n**Conservation ECBU :** < 2h à TA ou < 24h à +4°C"},
  {id:"abm_f2",title:"Hématologie : NFS et hémostase",bloc:"Bloc 2",tags:["Hématologie","NFS","Hémostase","Coagulation"],duree:20,niveau:"Intermédiaire",qbank:"abm_hemato",
    contenu:"**Valeurs normales NFS adulte :**\n• Hb : homme 13-17 g/dL, femme 12-16 g/dL\n• VGM : 80-100 fL (microcytose < 80, macrocytose > 100)\n• Leucocytes : 4-10 G/L\n• PNN : 50-70% des leucocytes\n• Plaquettes : 150-400 G/L\n\n**Anémies :**\n• Microcytaire hypochrome : carence martiale, thalassémie\n• Normocytaire normochrome arégénérative : aplasie, envahissement médullaire\n• Macrocytaire : carence B12/folates, hypothyroïdie, alcool\n\n**Hémostase :**\n• TP (voie extrinsèque) : facteurs I, II, V, VII, X → suivi AVK (INR)\n• TCA (voie intrinsèque) : facteurs VIII, IX, XI, XII → diagnostic hémophilie, suivi HNF\n• INR thérapeutique : 2-3 (FANV, MTEV)\n• D-Dimères : fibrinolyse → dépistage EP/TVP (VPN élevée)",
    ressources:[
      {titre:"BloodSpot — Atlas hématopoïétique",url:"https://bloodspot.eu/",type:"atlas",description:"ACTIVITÉ GUIDÉE : cherchez HBB (érythrocytes), MPO (PNN), CD19 (lymphocytes B), CD3E (lymphocytes T), ITGA2B (mégacaryocytes), CD34 (CSH). Identifiez dans quelles populations chaque gène est exprimé — corrélation directe avec la NFS."},
      {titre:"Human Protein Atlas — Blood Cell Types",url:"https://www.proteinatlas.org/humanproteome/blood+cell",type:"proteome",description:"Profils protéomiques de chaque type cellulaire sanguin : neutrophiles, monocytes, lymphocytes B et T, NK, érythrocytes, plaquettes. Vérifiez les marqueurs moléculaires des anémies (HBB, ALAS2) et des thrombopénies (ITGA2B, VWF)."},
      {titre:"CELLxGENE Gene Expression Explorer",url:"https://cellxgene.cziscience.com/gene-expression",type:"cellxgene",description:"Visualisez l'expression de CD34, HBB, MPO, F8, VWF dans les types cellulaires humains. Filtrez par tissu 'Blood' ou 'Bone marrow' pour cibler les cellules hématopoïétiques."}
    ]},
  {id:"abm_f3",title:"Biochimie médicale : marqueurs clés",bloc:"Bloc 2",tags:["Biochimie","Marqueurs","Bilan"],duree:22,niveau:"Intermédiaire",qbank:"abm_biochimie",
    contenu:"**Glycémie et diabète :**\n• À jeun < 5.6 mmol/L = normal\n• 2 glycémies > 7 mmol/L = diabète\n• HbA1c : glycémie moyenne 2-3 mois. Objectif < 7%\n\n**Fonction rénale :**\n• Créatinine : déchet métabolisme musculaire\n• DFG par formule CKD-EPI (mL/min/1.73m²)\n• Urée : catabolisme protéique (moins spécifique)\n\n**Bilan hépatique :**\n• ALAT : cytolyse hépatocytaire (très spécifique foie)\n• ASAT : moins spécifique (muscle, cœur, foie)\n• Bilirubine : ↑libre (hémolyse) ou ↑conjuguée (cholestase)\n• Phosphatases alcalines + GGT : cholestase\n\n**Marqueurs cardiaques :** Troponine I/T (H2-4 après nécrose)\n\n**Bilan thyroïdien :** TSH seule en dépistage\n\n**Inflammation :** CRP > 10 mg/L. Procalcitonine > 2 µg/L = bactérien sévère"},
  {id:"abm_f4",title:"Microbiologie médicale : ECBU et hémocultures",bloc:"Bloc 2",tags:["Microbiologie","ECBU","Hémocultures","Antibiogramme"],duree:20,niveau:"Intermédiaire",qbank:"abm_micro_med",
    contenu:"**ECBU :**\n• Recueil : milieu de jet du matin (après toilette locale)\n• Bandelette urinaire : dépistage (leucocytes + nitrites)\n• Significatif : leucocyturie ≥ 10⁴/mL ET bactériurie ≥ 10⁵ UFC/mL (E. coli)\n• 1ère cause : E. coli (80%). Milieux : CLED, CPS\n\n**Hémocultures :**\n• Avant antibiothérapie, au pic fébrile\n• 2-3 paires = augmente sensibilité (80-90%)\n• 8-10 mL/flacon adulte (aérobie + anaérobie)\n\n**Antibiogramme :**\n• Mueller-Hinton, disques antibiotiques\n• Lecture diamètre → S/I/R selon EUCAST\n• BLSE : résistance C3G (dépistage synergie)\n• SARM : disque céfoxitine ou PCR mecA\n\n**Milieux :** MacConkey (Gram-), Chapman (staphylocoques), Hektoen (Salmonella/Shigella), Karmali 42°C (Campylobacter)"},
  {id:"abm_f5",title:"Immunologie et sérologies",bloc:"Bloc 2",tags:["Immunologie","Sérologies","Transfusion","Auto-anticorps"],duree:18,niveau:"Intermédiaire",qbank:"abm_immuno",
    contenu:"**VIH :** ELISA 4G (Ag p24 + Ac) → confirmation Immunoblot. Délai fenêtre : 6 semaines.\n\n**Hépatite B :**\n• Ag HBs+ = porteur (aigu ou chronique)\n• Ac anti-HBs+ = immunité (vaccination ou guérison)\n• Ac anti-HBc+ = contact avec le virus\n\n**Toxoplasmose grossesse :**\n• IgG+ IgM- = ancienne, pas de risque\n• IgG- IgM- = séronégative → surveillance mensuelle\n\n**Immunohématologie :**\n• Groupage ABO : Beth-Vincent + Simonin concordants\n• RH1 : 2 réactifs monoclonaux\n• RAI : valide 72h en transfusion, obligatoire 28 SA\n\n**Auto-immunité :**\n• AAN : dépistage lupus (IFI sur HEp-2)\n• Facteur rhumatoïde : PR (peu spécifique)\n• Anti-CCP : plus spécifique de la PR\n• Coombs direct : Ac/C3d fixés sur GR → anémie hémolytique auto-immune"},
  ,{id:"abm_f6",title:"Parasitologie & mycologie médicale",bloc:"Bloc 2",tags:["Parasitologie","Mycologie","EPS","Paludisme"],duree:18,niveau:"Intermédiaire",qbank:"abm_parasito",
    contenu:"**Paludisme (urgence diagnostique) :**\n• Frottis mince + goutte épaisse (Giemsa) en urgence (< 2h)\n• TDR : HRP2 (P. falciparum) ou pLDH (toutes espèces)\n• P. falciparum : neuropaludisme (forme grave)\n• Résultat négatif n'exclut pas si suspicion clinique forte\n\n**EPS (Examen Parasitologique des Selles) :**\n• État frais + concentration (Ritchie) + coloration\n• 3 selles sur 3 jours différents\n• Test de Graham (scotch anal) pour oxyures\n\n**Protozoaires :**\n• Entamoeba histolytica : amibiase invasive (≠ E. dispar non pathogène)\n• Giardia : malabsorption duodéno-jéjunale\n• Cryptosporidium : Ziehl modifié (acido-résistant)\n• T. vaginalis : IST, examen direct à frais\n\n**Mycologie :**\n• Sabouraud + antibactériens : culture champignons\n• C. albicans : test filamentation + (2h sérum 37°C)\n• Dermatophytes : kératinophiles (Trichophyton spp.)\n• Aspergillus fumigatus : angio-invasif si immunodéprimé (galactomannane)"}
  ,{id:"abm_f7",title:"Biologie moléculaire : PCR et acides nucléiques",bloc:"Bloc 2",tags:["Biologie moléculaire","PCR","ADN","ARN"],duree:22,niveau:"Intermédiaire",qbank:"abm_bio_mol",
    contenu:"**Acides nucléiques :**\n• Nucléotide = base azotée + pentose + acide phosphorique\n• ADN : désoxyribose + A, T, G, C (double brin, noyau)\n• ARN : ribose + A, U, G, C (simple brin, cytoplasme)\n• Bases puriques : Adénine (A), Guanine (G)\n• Bases pyrimidiques : Cytosine (C), Thymine (T/ADN), Uracile (U/ARN)\n\n**PCR (Polymerase Chain Reaction) :**\n• Kary Mullis, 1985 (Prix Nobel 1993)\n• Réactifs : ADN matrice + amorces + Taq polymérase + dNTPs + tampon + MgCl₂\n• **3 étapes du cycle :**\n  1. Dénaturation : 90-95°C → séparation des brins\n  2. Hybridation : 50-65°C → fixation des amorces\n  3. Élongation : 72°C → synthèse par Taq polymérase\n• ~30 cycles → amplification exponentielle (×2³⁰ ≈ 10⁹ copies)\n\n**Variantes :**\n• PCR multiplex : plusieurs paires d'amorces (panels infectieux)\n• qPCR (temps réel) : quantification via fluorescence (Ct)\n• RT-PCR : ARN → ADNc (rétrotranscriptase) → PCR\n• Séquençage Sanger : ddNTPs, 200-1000 pb"}
  ,{id:"abm_f8",title:"Bactériologie : structure et identification",bloc:"Bloc 2",tags:["Bactériologie","Structure","Gram","Identification"],duree:20,niveau:"Fondations",qbank:"abm_bacterio_struct",
    contenu:"**Structure bactérienne :**\n• Procaryote : ADN circulaire sans noyau membranaire\n• Taille : 0.5-1 µm × 2-5 µm\n• Structures obligatoires : paroi, membrane, cytoplasme, ribosomes 70S, nucléoïde\n• Structures facultatives : capsule (anti-phagocytaire), plasmides, flagelles (mobilité), pili\n\n**Coloration de Gram :**\n• Gram+ = violet (peptidoglycane épais)\n• Gram- = rose (paroi mince + membrane externe LPS)\n\n**Identification :**\n• Gram+ coques → Catalase : + = Staphylocoques ; - = Streptocoques\n• Gram- → Oxydase : + = Pseudomonas/Neisseria ; - = Entérobactéries\n\n**Milieux :**\n• Gélose sang : exigeants + hémolyse (α-vert, β-transparent, γ-rien)\n• Mueller-Hinton : antibiogramme standardisé (EUCAST)\n• KIA/Hajna-Kliger : glucose, lactose, H2S, gaz (entérobactéries)"}
  ,{id:"abm_f9",title:"Contrôle qualité analytique et règles de Westgard",bloc:"Bloc 2",tags:["Contrôle qualité","CQI","CQA","Westgard","Levey-Jennings"],duree:22,niveau:"Avancé",qbank:"abm_cq",
    contenu:"**Outils du contrôle qualité interne (CQI) :**\n• Matériau de contrôle à valeurs cibles connues (sérum commercial lyophilisé) inclus dans chaque série analytique\n• Carte de Levey-Jennings : axe X = runs/jours ; axe Y = valeur mesurée. Lignes ±1DS, ±2DS, ±3DS tracées autour de la moyenne cible\n• Z-score = (valeur obtenue − moyenne cible) / DS\n\n**Règles de Westgard :**\n• **1:2s** — alerte : 1 valeur entre ±2DS et ±3DS → vigilance, ne rejette pas seul le run\n• **1:3s** — rejet : 1 valeur dépasse ±3DS → erreur aléatoire, run invalidé\n• **2:2s** — rejet : 2 valeurs consécutives du même côté entre ±2DS et ±3DS → erreur systématique (biais)\n• **R:4s** — rejet : écart max−min du run ≥ 4DS → imprécision\n• **4:1s** — rejet : 4 valeurs consécutives du même côté à ±1DS → dérive\n• **10:x** — rejet : 10 valeurs consécutives du même côté → tendance systématique\n\n**Exemple numérique :**\n• Glucose cible = 100 mg/dL, DS = 3 mg/dL\n• 1:3s déclenché si CQ < 91 mg/dL ou > 109 mg/dL\n\n**CQA — Évaluation Externe de la Qualité (EEQ) :**\n• Programme inter-laboratoires (ex : CTCB, Labquality)\n• Échantillons à valeurs inconnues → comparaison aux pairs\n• Obligatoire pour l'accréditation COFRAC ISO 15189\n\n**Indicateurs de performance analytique :**\n• Biais = erreur systématique (différence valeur mesurée vs valeur vraie)\n• CV (%) = DS / moyenne × 100 → mesure l'imprécision\n• TEa (Total Error Allowable) : erreur totale tolérée (CLIA / RiliBÄK)\n• Sigma = (TEa − biais) / CV → σ ≥ 6 = excellent ; σ < 3 = méthode à risque\n\n**Réglementation française :** GBEA (Guide de Bonne Exécution des Analyses), accréditation ISO 15189 (COFRAC)"}
  ,{id:"abm_f11",title:"Hémostase approfondie : coagulation, thrombophilies et anticoagulants",bloc:"Bloc 2",tags:["Hémostase","TP","TCA","INR","CIVD","Thrombophilie","Facteur V Leiden","ATIII","MvW"],duree:22,niveau:"Avancé",qbank:"abm_hemostase",
    contenu:"**Bilan hémostase de 1ère intention :**\n• TP (Taux de Quick) : voie extrinsèque (VII) + commune (X, V, II, I)\n• TCA : voie intrinsèque (VIII, IX, XI, XII) + commune\n• Plaquettes + fibrinogène\n\n**Interprétation :**\n• TP seul allongé : déficit VII, début AVK\n• TCA seul allongé : hémophilie A (FVIII↓), hémophilie B (FIX↓), héparine, anticoagulant lupique\n• TP + TCA allongés : AVK, insuffisance hépatocellulaire, CIVD, déficits voie commune\n• CIVD : TP↓ + TCA↑ + fibrinogène < 1 g/L + D-dimères >> + thrombopénie\n\n**Thrombophilies héréditaires :**\n• Facteur V Leiden (R506Q) : la + fréquente (5% Caucasiens), résistance PCa, TVP ×5-8\n• Mutation prothrombine G20210A (2-3%)\n• Déficits ATIII, protéine C, protéine S (rares, risque élevé)\n\n**Surveillance des anticoagulants :**\n• AVK : INR (cible 2-3 pour FA/MTEV ; 2.5-3.5 valve mécanique)\n• HNF : TCA (2-3× témoin) ou anti-Xa\n• HBPM : anti-Xa (si obésité, grossesse, IRC, pédiatrie)\n• AOD : pas de surveillance systématique\n\n**Maladie de von Willebrand type 1 :**\n• Déficit quantitatif FvW partiel → TCA allongé + TS allongé + FVIII légèrement ↓\n• Traitement : DDAVP (desmopressine)",
    ressources:[
      {titre:"BloodSpot — Facteurs de coagulation",url:"https://bloodspot.eu/",type:"atlas",description:"Recherchez VWF (facteur de Willebrand), F8 (facteur VIII), PROS1 (protéine S), PROC (protéine C), SERPINC1 (ATIII) dans les cellules hématopoïétiques et hépatiques. Complément visuel indispensable pour les thrombophilies héréditaires."},
      {titre:"Human Protein Atlas — Plasma Protéome",url:"https://www.proteinatlas.org/humanproteome/plasma+proteome",type:"proteome",description:"Carte des protéines plasmatiques incluant les facteurs de coagulation (fibrinogène, prothrombine, facteur V). Niveaux d'expression et tissu de synthèse de chaque facteur."}
    ]}
  ,{id:"abm_f12",title:"Immunohématologie et sécurité transfusionnelle",bloc:"Bloc 2",tags:["Groupage ABO","Rhésus","RAI","Transfusion","Gel-test","Coombs indirect","CGR","Plaquettes"],duree:20,niveau:"Intermédiaire",qbank:"abm_immuno_transf",
    contenu:"**Groupage ABO :**\n• Beth-Vincent (épreuve globulaire) : Ag sur GR patient\n• Simonin (épreuve sérique) : Ac dans le sérum patient\n• 2 déterminations concordantes obligatoires sur 2 prélèvements\n\n**Système RH :**\n• 5 Ag principaux : D(RH1), C(RH2), E(RH3), c(RH4), e(RH5)\n• Ag D = le plus immunogène (allo-immunisation si D+ transfusé à D-)\n• 2 réactifs monoclonaux obligatoires pour RH1\n\n**RAI :**\n• Recherche Ac irréguliers anti-GR dans le sérum du patient\n• Validité : 72h (si événement immunisant < 3 mois) ou 21 jours\n• Technique : gel-test (IAT) ou en tube\n\n**Gel-test (DiaMed) :**\n• Microcolonne de gel Sephadex → centrifugation\n• GR agglutinés en surface = positif / au fond = négatif\n• Avantages : standardisation, archivage, reproductibilité\n\n**Sécurité transfusionnelle :**\n• Incompatibilité ABO = accident hémolytique immédiat (mortel)\n• Hémolyse retardée : Ac anti-Rh (J5-J14)\n• CGR isogroupe (même ABO + RH1) ; phénotypé si risque\n• Dépistage néonatal Guthrie : 6 maladies (PCU, hypothyroïdie, HCS, drépanocytose, mucoviscidose, MCAD)"}
  ,{id:"abm_f13",title:"Biologie moléculaire clinique avancée : charges virales, oncologie et pharmacogénomique",bloc:"Bloc 2",tags:["PCR multiplex","Charge virale","RT-PCR","HER2","BRCA","MSI","DPYD","ctDNA","Métagénomique"],duree:24,niveau:"Avancé",qbank:"abm_biol_mol2",
    contenu:"**Charges virales et panels infectieux :**\n• qPCR (temps réel) : quantification par Ct (cycle seuil) → charge virale VIH, VHC, CMV, EBV\n• RT-PCR : ARN → ADNc (rétrotranscriptase) → PCR → VIH, VHC, SARS-CoV-2\n• PCR multiplex (FilmArray, NxTAG) : 10-30 cibles en 1-4h (panel respiratoire, panel méningite)\n\n**Oncobiologie moléculaire :**\n• HER2 IHC 2+ (équivoque) → confirmation FISH/ISH (ratio HER2/CEP17 ≥ 2 = amplifié → trastuzumab)\n• BRCA1/2 somatique : mutations tumorales → réponse inhibiteurs PARP (olaparib, niraparib)\n• MSI (instabilité microsatellitaire) : PCR (profils répétitions) OU IHC perte expression MLH1/MSH2/MSH6/PMS2\n  → MSI-H = anti-PD1 efficaces (pembrolizumab)\n• ctDNA (biopsie liquide) : détection mutations tumorales dans le sang (ddPCR ou NGS ultra-sensible)\n  → suivi MRM, résistances précoces aux traitements\n\n**Pharmacogénomique :**\n• DPYD : mutations → accumulation de 5-FU → toxicités sévères (mucites, neutropénies) → génotypage avant chimiothérapie\n• CYP2D6 : codéine, tamoxifène\n• TPMT/NUDT15 : mercaptopurine (myélosuppression)\n• UGT1A1 : irinotécan (diarrhées)\n\n**Séquençage de confirmation :**\n• Sanger (1 amplicon, < 1000 pb, résultat rapide) : confirmation de variants NGS\n• Array-CGH/CMA : CNV sur tout le génome (> 50-200 kb) — bilan anomalies développement\n• mNGS (métagénomique) : identification tous micro-organismes → infections non étiquetées, pathogènes émergents"}
  ,{id:"abm_f10",title:"Méthodes chromatographiques",bloc:"Bloc 2",tags:["Chromatographie","CCM","HPLC","CPG","Séparation"],duree:25,niveau:"Avancé",qbank:"abm_chromato",
    contenu:"**Principe général :** Séparation de composés par distribution entre une phase stationnaire (fixe) et une phase mobile (liquide ou gazeuse) qui la traverse. Chaque composé est caractérisé par son temps de rétention tR.\n\n**CCM (Chromatographie sur Couche Mince) — Tswett 1905 :**\n• Phase stationnaire : silice sur plaque aluminium/verre\n• Phase mobile : solvant organique\n• Rf = distance tache / distance front solvant (0 < Rf < 1)\n• Révélation : UV 254 nm (composés conjugués), ninhydrine (acides aminés), iode\n• Usage : contrôle de pureté, identification, suivi de réaction\n\n**HPLC (Chromatographie Liquide Haute Performance) :**\n• Pression 50-300 bars, colonne analytique 15-25 cm\n• **Phase inverse** (la plus courante) : stationnaire apolaire (C18) + mobile polaire/aqueuse\n• **Phase normale** : stationnaire polaire (silice) + mobile apolaire\n• Détecteurs : UV-Vis à longueur d'onde fixe, DAD (spectre complet), fluorescence, MS\n• Quantification par aire du pic (étalonnage externe ou interne)\n\n**CPG (Chromatographie en Phase Gazeuse) :**\n• Analyte doit être volatil (ou dérivé)\n• Gaz vecteur : hélium ou azote. Température : 50-300°C\n• Détecteurs : FID (composés carbonés, universel), ECD (halogénés), MS\n• Applications : solvants, alcools, arômes, parfums, pesticides\n\n**Techniques de purification :**\n• **SEC (Exclusion de taille)** : gel poreux → grosses molécules éluent en PREMIER. Protéines, polymères\n• **IEC (Échange d'ions)** : phase stationnaire chargée. Élution par gradient NaCl ou pH. Purification protéines, eau déionisée\n• **Affinité** : ligand spécifique immobilisé (Protéine A→IgG, Ni-NTA→His-tag, glutathion→GST). Très haute pureté en une étape\n• **Chirale** : colonne chirale → séparation énantiomères (D et L, R et S). Usage pharmaceutique\n\n**Paramètres d'efficacité :**\n• k' (facteur de rétention) = (tR − t0) / t0\n• N (plateaux théoriques) = L / H → grand N = pics fins = bonne résolution\n• Relation de Van Deemter : H = A + B/u + Cu (optimisation vitesse phase mobile)"}

  ,{id:"abm_f14",title:"Hématopoïèse & Cell Atlas — du CD34 aux cellules matures",bloc:"Bloc 2",tags:["Hématopoïèse","Cell Atlas","scRNA-seq","CD34","Différenciation","Lignées"],duree:25,niveau:"Avancé",qbank:"abm_hemato_cell",
    contenu:"## Arbre de différenciation\n\n### Cellules souches et progéniteurs\n| Population | Marqueurs | Potentiel |\n|-----------|---------|----------|\n| **CSH (LT-HSC)** | CD34+ CD38- CD45RA- | Auto-renouvellement + multi-lignée |\n| **MPP** | CD34+ CD38+ | Myéloïde + lymphoïde |\n| **CMP** | CD34+ CD38+ CD123+ | Myéloïde uniquement |\n| **CLP** | CD34+ CD38+ CD127+ | Lymphoïde uniquement |\n| **GMP** | CD34+ CD116+ | Granulocytes + monocytes |\n| **MEP** | CD34+ CD36+ | Mégacaryocytes + érythrocytes |\n\n### Gènes marqueurs clés (visibles sur BloodSpot)\n| Gène | Cellule | Pertinence clinique |\n|------|---------|---------------------|\n| **HBB** | Érythrocytes | Thalassémie, drépanocytose |\n| **MPO** | PNN, monocytes | LAM (blast MPO+) |\n| **CD19** | Lymphocytes B | LLC, LAL-B |\n| **CD3E** | Lymphocytes T | LAL-T |\n| **ITGA2B** | Mégacaryocytes | Thrombopénie |\n| **CD34** | CSH, progéniteurs | Leucémies aiguës précoces |\n\n## scRNA-seq appliqué à l'hémato\n\n### Principe en 4 étapes\n① Séquençage de chaque cellule individuellement (10x Chromium)\n② Profil de 20 000+ gènes par cellule\n③ UMAP : regroupement par similarité transcriptomique\n④ Pseudotemps : trajectoire du plus immature au plus mature\n\n### Avantages vs cytométrie de flux\n• Cytométrie : ~50 marqueurs protéiques max, rapide, clinique\n• scRNA-seq : 20 000+ gènes, découvre sous-populations inédites, recherche",
    ressources:[
      {titre:"BloodSpot — Hématopoïèse normale",url:"https://bloodspot.eu/",type:"atlas",description:"ACTIVITÉ GUIDÉE : cherchez HBB, MPO, CD19, CD3E, ITGA2B et CD34. Pour chaque gène, identifiez dans quelles populations il est exprimé et corréllez avec la NFS."},
      {titre:"CELLxGENE Gene Expression — Moelle osseuse",url:"https://cellxgene.cziscience.com/gene-expression",type:"cellxgene",description:"Sélectionnez le tissu Bone marrow ou Blood. Entrez CD34, MPO, HBB, CD19 et observez la spécificité de chaque gène par lignée."},
      {titre:"Human Cell Atlas — Blood & Bone Marrow",url:"https://www.humancellatlas.org/",type:"atlas",description:"Datasets publiés de moelle osseuse humaine saine. Visualisez les UMAP de différenciation et les gènes différentiellement exprimés entre CSH et cellules matures."},
      {titre:"Human Protein Atlas — Blood Cell Types",url:"https://www.proteinatlas.org/humanproteome/blood+cell",type:"proteome",description:"Corrélation transcriptomique (BloodSpot) vs niveaux protéiques. Comprendre les discordances ARNm / protéine."}
    ]},
  ,{id:"abm_f15",title:"Immunophénotypage : des marqueurs CD aux profils transcriptomiques",bloc:"Bloc 2",tags:["Immunophénotypage","Cytométrie","CD markers","scRNA-seq","LAM","LLC","NK"],duree:22,niveau:"Avancé",qbank:"abm_immunopheno_cell",
    contenu:"## Marqueurs CD et cytométrie de flux\n\n### Correspondance CD → type cellulaire\n| Marqueur | Type cellulaire | Gène correspondant |\n|----------|---------------|---------------------|\n| **CD34** | CSH, progéniteurs | CD34 |\n| **CD3** | Lymphocytes T | CD3E/D/G |\n| **CD4** | LT auxiliaires | CD4 |\n| **CD8** | LT cytotoxiques | CD8A |\n| **CD19** | Lymphocytes B | CD19 |\n| **CD20** | Lymphocytes B matures | MS4A1 |\n| **CD14** | Monocytes | CD14 |\n| **CD56** | Cellules NK | NCAM1 |\n| **CD13/CD33** | Lignée myéloïde | ANPEP/SIGLEC3 |\n| **MPO** | PNN, monocytes | MPO |\n\n## Profils pathologiques\n\n### LLC\n• CD5+ CD19+ CD23+ + FMC7- + Ig faible\n• Score de Matutes ≥4/5 = LLC\n• Cibles : BTK (ibrutinib), BCL2 (venetoclax)\n\n### LAM\n• CD13+ CD33+ CD117+ MPO+ ± CD34+\n• Blastes ≥20% moelle osseuse\n\n### LAL-B vs LAL-T\n| | LAL-B | LAL-T |\n|--|-------|-------|\n| Marqueurs | CD19+ TdT+ | CD3+ TdT+ |\n| Cible thérapeutique | Blinatumomab | — |\n\n## Corrélation cytométrie / scRNA-seq\n• Cytométrie : rapide, clinique, ~50 marqueurs max\n• scRNA-seq : transcriptome complet, découvre des sous-populations (monocytes classiques vs non classiques)\n• Discordances possibles : régulation post-transcriptionnelle",
    ressources:[
      {titre:"Human Protein Atlas — Immune Cell Atlas",url:"https://www.proteinatlas.org/humanproteome/immune+cell",type:"proteome",description:"ACTIVITÉ : pour chaque marqueur CD du cours (CD3, CD4, CD8, CD14, CD19, CD20, CD56), vérifiez quel type cellulaire l'exprime. Comparez les niveaux d'expression protéique CD4 vs CD8."},
      {titre:"CELLxGENE — Profils cellulaires",url:"https://cellxgene.cziscience.com/gene-expression",type:"cellxgene",description:"Cherchez MPO, CD14, CD19, CD3E dans le tissu sanguin. Observez comment ces marqueurs distinguent les types cellulaires en scRNA-seq."},
      {titre:"BloodSpot — Marqueurs thérapeutiques",url:"https://bloodspot.eu/",type:"atlas",description:"Recherchez BTK (ibrutinib), FLT3 (midostaurine), BCL2 (venetoclax). Pour chaque gène, identifiez dans quelle population normale il est exprimé — cela explique pourquoi ces molécules sont des cibles thérapeutiques."}
    ]}
  ,{id:"abm_f16",title:"Identification morphologique des cellules sanguines — lame MGG",
    bloc:"Bloc 2",tags:["Frottis","MGG","Morphologie","Leucocytes","Érythrocytes","Blastes","Identification"],
    duree:50,niveau:"Intermédiaire",qbank:"abm_hemato_visual",
    contenu:"## 🔬 Critères d'identification MGG — leucocytes\n\n| Cellule | Taille (µm) | Noyau | Cytoplasme | Granulations |\n|---------|------------|-------|------------|--------------|\n| **PNN segmenté** | 10-15 | Multilobé (2-5 lobes) | Rose pâle | Fines neutrophiles |\n| **PNE** | 12-17 | Bilobé | Rose | Grands, orangés |\n| **PNB** | 10-14 | Bilobé irrégulier | Peu visible | Très grands, violet-noir |\n| **Lymphocyte** | 7-12 | Rond, dense | Fin liseré bleu | Rares azurophiles |\n| **Monocyte** | 12-20 | Rein/fer à cheval | Gris-bleuté | Fins, vacuoles |\n\n## 🩸 Hématies anormales — morphologie et orientation diagnostique\n\n• **Annulocyte** (zone centrale élargie) → carence martiale (hypochromie)\n• **Sphérocyte** (rond, sans pallor) → sphérocytose héréditaire, AHAI\n• **Drépanocyte** (en faucille) → drépanocytose HbSS\n• **Cellule cible** (en tir à la corde) → thalassémie, hépatopathie\n• **Schizocyte** (fragment anguleux) → microangiopathie thrombotique (PTT, SHU)\n• **Dacryocyte** (en larme) → myélofibrose, envahissement médullaire\n• **Acanthocyte** (épines irrégulières) → abêtalipoprotéinémie, cirrhose sévère\n\n## 🧬 Reconnaître un blast — critères OMS\n\n**Blast myéloïde (LAM)** : noyau volumineux + 1-3 nucléoles visibles + chromatine lâche + cytoplasme basophile ± corps d'Auer (pathognomonique LAM).\n**Blast lymphoïde (LAL)** : noyau arrondi, chromatine condensée, cytoplasme très réduit, TdT+.\n→ Seuil diagnostique : ≥ 20 % blastes dans le sang ou la moelle osseuse (critères OMS 2022).\n\n## 📏 Série érythroïde — séquence de maturation (moelle → sang)\n\n① **Proérythroblaste** : 18-25 µm, très basophile, nucléoles visibles\n② **Érythroblaste basophile** : 12-18 µm, noyau dense, cytoplasme bleu intense\n③ **Érythroblaste polychromatophile** : cytoplasme bleu-rose (début synthèse HbA)\n④ **Érythroblaste orthochromatophile** : cytoplasme rose, noyau pycnotique\n⑤ **Réticulocyte** : noyau expulsé, réticulum ARN visible au bleu de crésyl brillant\n⑥ **Érythrocyte mature** : biconcave, 7-8 µm, anucléé, durée de vie 120 jours\n\n## 💡 Technique MGG — points-clés pour l'examen\n\n→ **May-Grünwald** : colore les éléments éosinophiles (noyaux, granules)\n→ **Giemsa** : colore les éléments basophiles + spécifique des granulations (éosino/baso/neutro)\n→ Grossissement **×1000** à l'immersion obligatoire pour la formule leucocytaire\n→ Zone de lecture = zone où 50 % des hématies ne se touchent pas (ni amassées ni isolées)\n→ Comptage de **100 leucocytes** pour la formule différentielle",
    ressources:[
      {titre:"ASH Image Bank — Atlas morphologie hématologique",url:"https://imagebank.hematology.org/",type:"atlas",description:"ACTIVITÉ : parcourez les catégories Leukocyte Disorders et Red Cell Disorders. Identifiez chaque image avant de lire la légende — simulez la lecture de frottis."},
      {titre:"Human Protein Atlas — Blood Cell Types",url:"https://www.proteinatlas.org/humanproteome/blood+cell",type:"proteome",description:"Corrélation entre morphologie MGG et profil protéique de chaque type leucocytaire. Utile pour comprendre les marqueurs d'identification en cytométrie."},
      {titre:"BloodSpot — Hématopoïèse et expression génique",url:"https://bloodspot.eu/",type:"atlas",description:"Observez l'expression de MPO (PNN), CD19 (lymphocyte B), CD3E (lymphocyte T), CD14 (monocyte). Corréllez avec la morphologie MGG."},
      {titre:"CELLxGENE — Tissu sanguin humain",url:"https://cellxgene.cziscience.com/gene-expression",type:"cellxgene",description:"Sélectionnez Blood comme tissu. Visualisez comment chaque type cellulaire est distingué par son profil transcriptomique — complément des critères morphologiques."}
    ]}
  ,...FICHES_PC
];

